"use client";

import { useState, useEffect, useCallback } from 'react';
import TopNav from '@/components/layout/TopNav';
import PlanWizard from '@/components/plan/PlanWizard';
import { useApp } from '@/lib/context';
import { supabase } from '@/lib/supabase';

const PLAN_KEY = 'altitud_business_plan';

function loadLocalPlan() {
  if (typeof window === 'undefined') return null;
  try {
    const raw = localStorage.getItem(PLAN_KEY);
    if (raw) return JSON.parse(raw);
  } catch { /* ignore */ }
  return null;
}

export default function PlanClient({ initialPlan }) {
  const { t } = useApp();
  const [existingPlan, setExistingPlan] = useState(initialPlan);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!initialPlan) {
      const local = loadLocalPlan();
      if (local) setExistingPlan(local);
    }
    setLoading(false);
  }, [initialPlan]);

  // Save (upsert) to Supabase
  const handleSave = useCallback(async (planData) => {
    const payload = {
      agent_email: planData.agent_email || 'default@altitud.cr',
      agent_name: planData.agent_name || 'Agente',
      para_que: planData.para_que,
      currency: planData.currency,
      exchange_rate: planData.exchange_rate,
      living_expenses: planData.living_expenses,
      total_living_monthly: planData.total_living_monthly,
      business_expenses: planData.business_expenses,
      total_business_monthly: planData.total_business_monthly,
      goals: planData.goals,
      total_goals_monthly: planData.total_goals_monthly,
      grand_total_monthly: planData.grand_total_monthly,
      grand_total_monthly_usd: planData.grand_total_monthly_usd,
      avg_ticket: planData.avg_ticket,
      ticket_currency: planData.ticket_currency,
      commission_pct: planData.commission_pct,
      agent_split_pct: planData.agent_split_pct,
      commission_per_close: planData.commission_per_close,
      closes_needed_monthly: planData.closes_needed_monthly,
      conversion_ratios: planData.conversion_ratios,
      monthly_targets: planData.monthly_targets,
      weekly_targets: planData.weekly_targets,
      monthly_targets_by_month: planData.monthly_targets_by_month || [],
      target_portfolio_size: planData.target_portfolio_size || 25,
      plan_start_date: planData.plan_start_date || '',
      status: planData.status || 'draft',
    };

    try {
      const { error } = await supabase
        .from('business_plans')
        .upsert(payload, { onConflict: 'agent_email' });

      if (error) {
        console.warn('Supabase save failed, saving to localStorage:', error.message);
      }
    } catch (e) {
      console.warn('Supabase unavailable, saving to localStorage:', e.message);
    }

    // Always save to localStorage as backup + for OKR integration
    localStorage.setItem(PLAN_KEY, JSON.stringify(planData));
    localStorage.setItem('altitud_okr_plan', JSON.stringify({
      monthly_targets: planData.monthly_targets || {},
      weekly_targets: planData.weekly_targets || {},
      monthly_targets_by_month: planData.monthly_targets_by_month || [],
      plan_start_date: planData.plan_start_date || '',
      target_portfolio_size: planData.target_portfolio_size || 25,
    }));
  }, []);

  const handleComplete = useCallback(async (planData) => {
    await handleSave({ ...planData, status: 'active', completed_at: new Date().toISOString() });
    // Navigate back to OKR
    window.location.href = '/';
  }, [handleSave]);

  const handleSaveDraft = useCallback(async (planData) => {
    await handleSave({ ...planData, status: 'draft' });
  }, [handleSave]);

  if (loading) {
    return (
      <>
        <TopNav titleKey="pw_page_title" subtitleKey="pw_page_subtitle" />
        <div className="flex-1 flex items-center justify-center">
          <div className="animate-pulse text-gray-400 dark:text-gray-500 text-sm font-bold uppercase tracking-widest">
            {t('pw_saving')}...
          </div>
        </div>
      </>
    );
  }

  return (
    <>
      <TopNav titleKey="pw_page_title" subtitleKey="pw_page_subtitle" />
      <PlanWizard
        existingPlan={existingPlan}
        onComplete={handleComplete}
        onSaveDraft={handleSaveDraft}
      />
    </>
  );
}

"use client";

import { useState } from 'react';
import Image from 'next/image';

export default function PortalClient({ search, initialPipeline }) {
  const [voterName, setVoterName] = useState('');
  const [isIdentified, setIsIdentified] = useState(false);
  const [pipeline, setPipeline] = useState(initialPipeline);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [viewMode, setViewMode] = useState('tinder'); // 'tinder' or 'matrix'

  const agent = search.profiles;
  const mustHaves = search.must_haves || [];
  const niceToHaves = search.nice_to_haves || [];

  // Filter out items that have already been voted on by this voter, or just show them all and let them override?
  // Let's show all and highlight if they already voted, or just let them vote on the remaining ones.
  const unvotedItems = pipeline.filter(p => !p.votes.some(v => v.voter_name.toLowerCase() === voterName.toLowerCase() && v.decision));

  const handleIdentify = (e) => {
    e.preventDefault();
    if (voterName.trim()) {
      setIsIdentified(true);
    }
  };

  const handleVote = async (pipeline_id, decision, rating = null) => {
    setSubmitting(true);
    try {
      const res = await fetch('/api/portal/votes', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          pipeline_id,
          voter_name: voterName,
          decision,
          rating
        })
      });

      if (res.ok) {
        const { vote } = await res.json();
        // Update local state
        setPipeline(prev => prev.map(p => {
          if (p.pipeline_id === pipeline_id) {
            return { ...p, votes: [...p.votes, vote] };
          }
          return p;
        }));
        // Move to next item if in tinder mode
        if (viewMode === 'tinder' && currentIndex < unvotedItems.length - 1) {
          setCurrentIndex(c => c + 1);
        }
      }
    } catch (err) {
      console.error(err);
      alert("Error al enviar el voto. Intenta nuevamente.");
    } finally {
      setSubmitting(false);
    }
  };

  if (!isIdentified) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4">
        <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl max-w-md w-full p-8 text-center border border-slate-100 dark:border-slate-700">
          {agent?.avatar_url && (
            <img src={agent.avatar_url} alt={agent.full_name} className="w-20 h-20 rounded-full mx-auto mb-4 border-4 border-brand-50" />
          )}
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">¡Hola!</h1>
          <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
            {agent?.full_name} ha preparado una selección de propiedades basada en tus requerimientos para <strong>{search.property_type}</strong>.
          </p>
          <form onSubmit={handleIdentify}>
            <input 
              type="text" 
              placeholder="¿Cuál es tu nombre?" 
              value={voterName}
              onChange={(e) => setVoterName(e.target.value)}
              className="w-full text-center text-lg px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-600 focus:outline-none focus:ring-2 focus:ring-brand-500 mb-4 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white"
              required
            />
            <button type="submit" className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-3 px-4 rounded-xl transition-all shadow-md">
              Ver Propiedades
            </button>
            <p className="text-xs text-slate-400 mt-4">Si estás buscando en pareja, cada uno puede ingresar con su propio nombre para votar de forma independiente.</p>
          </form>
        </div>
      </div>
    );
  }

  const currentItem = unvotedItems[currentIndex];

  return (
    <div className="max-w-4xl mx-auto pb-20">
      {/* Header Banner */}
      <div className="bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 p-4 sticky top-0 z-10 flex items-center justify-between shadow-sm">
        <div className="flex items-center space-x-3">
          {agent?.avatar_url ? (
            <img src={agent.avatar_url} alt={agent.full_name} className="w-10 h-10 rounded-full" />
          ) : (
            <div className="w-10 h-10 rounded-full bg-brand-100 flex items-center justify-center text-brand-600 font-bold">
              {agent?.full_name?.charAt(0)}
            </div>
          )}
          <div>
            <p className="text-xs text-slate-500 dark:text-slate-400 leading-tight">Preparado por</p>
            <p className="font-bold text-sm text-slate-900 dark:text-white leading-tight">{agent?.full_name}</p>
          </div>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-900 rounded-lg p-1">
          <button 
            onClick={() => setViewMode('tinder')} 
            className={`px-3 py-1.5 text-xs font-medium rounded-md transition-all ${viewMode === 'tinder' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Descubrir
          </button>
          <button 
            onClick={() => setViewMode('matrix')} 
            className={`px-3 py-1.5 text-xs font-medium rounded-md transition-all ${viewMode === 'matrix' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Comparar
          </button>
        </div>
      </div>

      {viewMode === 'tinder' && (
        <div className="p-4 md:p-8 mt-4">
          {!currentItem ? (
            <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-3xl border border-slate-100 dark:border-slate-700">
              <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
              </div>
              <h2 className="text-2xl font-bold text-slate-900 dark:text-white">¡Todo al día, {voterName}!</h2>
              <p className="text-slate-500 mt-2">Has revisado todas las propiedades enviadas por {agent?.full_name}.</p>
              <button onClick={() => setViewMode('matrix')} className="mt-6 text-brand-600 font-medium hover:underline">Ver resumen de evaluación</button>
            </div>
          ) : (
            <div className="max-w-md mx-auto bg-white dark:bg-slate-800 rounded-[32px] overflow-hidden shadow-2xl border border-slate-100 dark:border-slate-700 relative">
              {/* Image Carousel (Simplified for now, taking first image or generic) */}
              <div className="aspect-[4/5] relative bg-slate-200 dark:bg-slate-700">
                {currentItem.details.main_image_url || currentItem.details.image_urls?.[0] ? (
                  <img src={currentItem.details.main_image_url || currentItem.details.image_urls[0]} alt="Propiedad" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-slate-400">Sin foto</div>
                )}

                {/* Info Overlay */}
                <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/80 via-black/40 to-transparent p-6 pt-20">
                  <div className="flex justify-between items-end">
                    <div>
                      <h2 className="text-white text-2xl font-bold nexus-header leading-tight">
                        {currentItem.details.name || 'Propiedad Confidencial'}
                      </h2>
                      <p className="text-white/80 text-sm mt-1">{currentItem.details.location || currentItem.details.zone || 'Ubicación protegida'}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-white font-black text-xl">${Number(currentItem.details.list_price || 0).toLocaleString()}</p>
                    </div>
                  </div>

                  {/* Quick Stats */}
                  <div className="flex space-x-3 mt-4">
                    {(currentItem.details.bedrooms || currentItem.details.beds) && (
                      <div className="bg-white/20 backdrop-blur-md text-white text-xs px-2 py-1 rounded-md font-medium">
                        {currentItem.details.bedrooms || currentItem.details.beds} Cuartos
                      </div>
                    )}
                    {(currentItem.details.bathrooms || currentItem.details.baths) && (
                      <div className="bg-white/20 backdrop-blur-md text-white text-xs px-2 py-1 rounded-md font-medium">
                        {currentItem.details.bathrooms || currentItem.details.baths} Baños
                      </div>
                    )}
                    {currentItem.details.construction_size && (
                      <div className="bg-white/20 backdrop-blur-md text-white text-xs px-2 py-1 rounded-md font-medium">
                        {currentItem.details.construction_size} m²
                      </div>
                    )}
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="p-6 flex justify-center items-center space-x-6 bg-slate-50 dark:bg-slate-900">
                <button 
                  disabled={submitting}
                  onClick={() => handleVote(currentItem.pipeline_id, 'descartar')}
                  className="w-16 h-16 rounded-full bg-white dark:bg-slate-800 shadow-lg border border-red-100 flex items-center justify-center text-red-500 hover:scale-110 transition-transform disabled:opacity-50"
                >
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                </button>
                <button 
                  disabled={submitting}
                  onClick={() => handleVote(currentItem.pipeline_id, 'visita', 5)}
                  className="w-20 h-20 rounded-full bg-brand-500 shadow-xl shadow-brand-500/30 text-white flex items-center justify-center hover:scale-110 transition-transform disabled:opacity-50"
                >
                  <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd"></path></svg>
                </button>
                <button 
                  disabled={submitting}
                  onClick={() => handleVote(currentItem.pipeline_id, 'interesado', 3)}
                  className="w-16 h-16 rounded-full bg-white dark:bg-slate-800 shadow-lg border border-yellow-100 flex items-center justify-center text-yellow-500 hover:scale-110 transition-transform disabled:opacity-50"
                  title="Tal vez..."
                >
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 15l7-7 7 7"></path></svg>
                </button>
              </div>
            </div>
          )}

          <p className="text-center text-xs text-slate-400 mt-6">
            Desliza o usa los botones. <strong className="text-red-500">X</strong> descarta, <strong className="text-brand-500">Corazón</strong> solicita visita, <strong className="text-yellow-500">Flecha</strong> la guarda para después.
          </p>
        </div>
      )}

      {viewMode === 'matrix' && (
        <div className="p-4 md:p-8">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
            <div className="p-5 border-b border-slate-100 dark:border-slate-700">
              <h2 className="text-lg font-bold text-slate-900 dark:text-white nexus-header">Resumen de Evaluación</h2>
              <p className="text-xs text-slate-500 mt-1">Compara los indicadores clave de las propiedades.</p>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm whitespace-nowrap">
                <thead className="bg-slate-50 dark:bg-slate-900/50 text-slate-500 dark:text-slate-400">
                  <tr>
                    <th className="px-6 py-4 font-medium">Propiedad</th>
                    <th className="px-6 py-4 font-medium text-center border-r border-slate-200 dark:border-slate-700">Votos Familiares</th>
                    {mustHaves.map(param => (
                      <th key={param} className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400 border-r border-slate-200 dark:border-slate-700">{param}</th>
                    ))}
                    {niceToHaves.map(param => (
                      <th key={param} className="px-6 py-4 font-medium text-blue-600 dark:text-blue-400 border-r border-slate-200 dark:border-slate-700">{param}</th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                  {pipeline.map(p => {
                    const uniqueVoters = Array.from(new Set(p.votes.map(v => v.voter_name)));

                    return (
                      <tr key={p.pipeline_id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50">
                        <td className="px-6 py-4">
                          <div className="flex items-center space-x-3">
                            <div className="w-10 h-10 rounded-lg bg-slate-200 dark:bg-slate-700 overflow-hidden flex-shrink-0">
                              {p.details.main_image_url || p.details.image_urls?.[0] ? (
                                <img src={p.details.main_image_url || p.details.image_urls[0]} alt="Prop" className="w-full h-full object-cover" />
                              ) : null}
                            </div>
                            <div>
                              <p className="font-bold text-slate-900 dark:text-white">{p.details.name || 'Propiedad Confidencial'}</p>
                              <p className="text-xs text-slate-500">${Number(p.details.list_price || 0).toLocaleString()}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-center border-r border-slate-200 dark:border-slate-700">
                          <div className="flex flex-col gap-1 items-center">
                            {uniqueVoters.length > 0 ? uniqueVoters.map(vn => {
                              const vVote = p.votes.filter(v => v.voter_name === vn).pop();
                              if(!vVote) return null;
                              return (
                                <span key={vn} className={`inline-flex items-center px-2 py-1 rounded-full text-[10px] font-bold ${
                                  vVote.decision === 'descartar' ? 'bg-red-100 text-red-600' :
                                  vVote.decision === 'visita' ? 'bg-green-100 text-green-600' : 'bg-brand-100 text-brand-600'
                                }`}>
                                  {vn}: {vVote.decision.charAt(0).toUpperCase() + vVote.decision.slice(1)}
                                </span>
                              )
                            }) : (
                              <span className="text-xs text-slate-400">- Sin votos -</span>
                            )}
                          </div>
                        </td>
                        {mustHaves.map(param => {
                           const match = p.requirements_match?.[param];
                           return (
                             <td key={param} className="px-6 py-4 text-center border-r border-slate-200 dark:border-slate-700">
                               {match === true ? '✅' : match === false ? '❌' : '-'}
                             </td>
                           )
                        })}
                        {niceToHaves.map(param => {
                           const match = p.requirements_match?.[param];
                           return (
                             <td key={param} className="px-6 py-4 text-center border-r border-slate-200 dark:border-slate-700">
                               {match === true ? '✅' : match === false ? '❌' : '-'}
                             </td>
                           )
                        })}
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { useApp } from '@/lib/context';
import { useAuth } from '@/lib/auth-context';
import { supabase } from '@/lib/supabase';
import TopNav from '@/components/layout/TopNav';
import PropertyStatusBadge from '@/components/propiedades/PropertyStatusBadge';
import PropertyTimeline from '@/components/propiedades/PropertyTimeline';
import { PROPERTY_TYPES, formatPrice } from '@/components/propiedades/PropertyCard';
import SyndicationPanel from '@/components/propiedades/SyndicationPanel';
import CommissionCalculator from '@/components/propiedades/CommissionCalculator';
import SoldCongratsModal from '@/components/propiedades/SoldCongratsModal';
import ListingAnalyticsPanel from '@/components/propiedades/ListingAnalyticsPanel';
import Link from 'next/link';

const AMENITY_LABELS = {
  pool_private: { es: 'Piscina', en: 'Pool' },
  garage: { es: 'Garaje', en: 'Garage' },
  cooling: { es: 'A/C', en: 'A/C' },
  has_view: { es: 'Vista', en: 'View' },
  gated_community: { es: 'Condominio', en: 'Gated Community' },
  furnished: { es: 'Amueblado', en: 'Furnished' },
  maid_room: { es: 'Cuarto Servicio', en: 'Maid Room' },
  property_new: { es: 'Nuevo', en: 'New Construction' },
};

function InfoRow({ label, value }) {
  if (!value && value !== 0) return null;
  return (
    <div className="flex justify-between py-2 border-b border-gray-100 dark:border-dark-border last:border-0">
      <span className="text-sm text-gray-500 dark:text-gray-400">{label}</span>
      <span className="text-sm font-medium text-gray-900 dark:text-white text-right max-w-[60%]">{value}</span>
    </div>
  );
}

function SectionCard({ title, icon, children }) {
  return (
    <div className="glass-panel rounded-2xl p-5 mb-4">
      <h3 className="text-sm font-bold text-gray-800 dark:text-white mb-3 flex items-center gap-2">
        <span>{icon}</span> {title}
      </h3>
      {children}
    </div>
  );
}

export default function PropertyDetailClient({ initialProperty, initialImages, initialMilestones }) {
  const { id } = useParams();
  const router = useRouter();
  const { t, lang } = useApp();
  const { user, isBroker } = useAuth();
  const [property, setProperty] = useState(initialProperty);
  const [images, setImages] = useState(initialImages || []);
  const [loading, setLoading] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);
  const [milestones, setMilestones] = useState(initialMilestones);
  const [creatingFolder, setCreatingFolder] = useState(false);
  const [syncingPhotos, setSyncingPhotos] = useState(false);
  const [showSoldModal, setShowSoldModal] = useState(false);
  const [showCongratsModal, setShowCongratsModal] = useState(false);
  const [soldResult, setSoldResult] = useState(null);

  const fetchProperty = async () => {
    const { data, error } = await supabase
      .from('properties')
      .select('*, property_images(id, image_url, thumbnail_url, priority, drive_file_id)')
      .eq('id', id)
      .single();
    if (error) { console.error(error); setLoading(false); return; }
    setProperty(data);
    setImages((data.property_images || []).sort((a, b) => a.priority - b.priority));
    // Fetch milestones
    const { data: msData } = await supabase
      .from('listing_milestones')
      .select('*')
      .eq('property_id', id)
      .single();
    if (msData) setMilestones(msData);
    setLoading(false);
  };

  // Removed initial fetch useEffect, keep fetchProperty for refreshing data

  const updateStatus = async (newStatus, notes = null) => {
    setActionLoading(true);
    try {
      const updates = { status: newStatus };
      if (newStatus === 'pending_approval') updates.submitted_at = new Date().toISOString();
      if (notes !== undefined && notes !== null) updates.broker_notes = notes;
      const { error } = await supabase.from('properties').update(updates).eq('id', id);
      if (error) throw error;
      setProperty(p => ({ ...p, ...updates }));

      // Auto-update listing milestones
      const milestoneUpdate = { property_id: id, agent_id: user?.id };
      if (newStatus === 'pending_approval') milestoneUpdate.submitted_at = new Date().toISOString();
      if (newStatus === 'approved') milestoneUpdate.broker_approved_at = new Date().toISOString();
      if (newStatus === 'published') milestoneUpdate.published_at = new Date().toISOString();
      await supabase.from('listing_milestones').upsert(milestoneUpdate, { onConflict: 'property_id' });

      // Re-fetch milestones to update the timeline
      const { data: msData } = await supabase.from('listing_milestones').select('*').eq('property_id', id).single();
      if (msData) setMilestones(msData);
    } catch (err) {
      alert('Error: ' + err.message);
    } finally {
      setActionLoading(false);
    }
  };

  // Create Drive photo folder
  const handleCreateFolder = async () => {
    if (!property) return;
    setCreatingFolder(true);
    try {
      const agentName = user?.user_metadata?.full_name || user?.email?.split('@')[0] || 'Agent';
      const agentEmail = user?.email || null;
      const propertyName = property.name || property.listing_title_es || `Propiedad-${id.slice(0, 8)}`;

      const res = await fetch('/api/drive/create-folder', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ agentName, agentEmail, propertyName }),
      });
      const data = await res.json();
      if (data.success) {
        const { error } = await supabase.from('properties').update({
          drive_photos_folder_id: data.folderId,
          drive_photos_folder_url: data.folderUrl,
        }).eq('id', id);
        if (!error) {
          setProperty(p => ({
            ...p,
            drive_photos_folder_id: data.folderId,
            drive_photos_folder_url: data.folderUrl,
          }));
        }
      } else {
        alert('Error: ' + (data.error || 'Failed to create folder'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    } finally {
      setCreatingFolder(false);
    }
  };

  // Sync photos from Drive
  const handleSyncPhotos = async () => {
    setSyncingPhotos(true);
    try {
      const res = await fetch('/api/properties/sync-photos', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ propertyId: id }),
      });
      const data = await res.json();
      if (data.success) {
        alert(lang === 'en'
          ? `Synced ${data.synced} new photos (${data.total_images} total)`
          : `Sincronizadas ${data.synced} fotos nuevas (${data.total_images} total)`
        );
        fetchProperty(); // Reload to show new images
      } else {
        alert('Error: ' + (data.error || 'Unknown error'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    } finally {
      setSyncingPhotos(false);
    }
  };

  // Delete image
  const handleDeleteImage = async (imageId) => {
    if (!confirm(lang === 'en' ? 'Delete this photo?' : '¿Eliminar esta foto?')) return;
    const { error } = await supabase.from('property_images').delete().eq('id', imageId);
    if (!error) {
      setImages(prev => prev.filter(i => i.id !== imageId));
    }
  };

  if (loading) return (
    <>
      <TopNav titleKey="nav_properties" subtitleKey="nav_portfolio" />
      <div className="flex-1 flex items-center justify-center bg-slate-50 dark:bg-dark-bg">
        <div className="w-8 h-8 border-2 border-brand-500 border-t-transparent rounded-full animate-spin" />
      </div>
    </>
  );

  if (!property) return (
    <>
      <TopNav titleKey="nav_properties" subtitleKey="nav_portfolio" />
      <div className="flex-1 flex items-center justify-center bg-slate-50 dark:bg-dark-bg">
        <div className="text-center">
          <p className="text-gray-500">{lang === 'en' ? 'Property not found' : 'Propiedad no encontrada'}</p>
          <Link href="/propiedades" className="text-brand-500 text-sm mt-2 inline-block">← {t('nav_properties')}</Link>
        </div>
      </div>
    </>
  );

  const p = property;
  const title = (lang === 'en' ? p.listing_title_en : p.listing_title_es) || p.name;
  const typeLabel = p.property_type_id ? (PROPERTY_TYPES[p.property_type_id]?.[lang] || p.property_type || '') : '';
  const amenities = Object.entries(AMENITY_LABELS).filter(([k]) => p[k]).map(([k, v]) => lang === 'en' ? v.en : v.es);
  const canEdit = p.status === 'draft' || p.status === 'needs_changes';

  // Days on market
  const daysOnMarket = p.submitted_at
    ? Math.floor((Date.now() - new Date(p.submitted_at).getTime()) / (1000 * 60 * 60 * 24))
    : null;

  return (
    <>
      <TopNav titleKey="nav_properties" subtitleKey="nav_portfolio" />
      <div className="flex-1 flex flex-col h-full bg-slate-50 dark:bg-dark-bg p-4 md:p-8 overflow-y-auto w-full">
        <div className="max-w-5xl w-full mx-auto">

          {/* Breadcrumb */}
          <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400 mb-4">
            <Link href="/propiedades" className="hover:text-brand-500 transition-colors">{t('nav_properties')}</Link>
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
            <span className="text-gray-800 dark:text-white font-medium truncate max-w-[200px]">{title}</span>
          </div>

          {/* Broker Notes Banner */}
          {p.status === 'needs_changes' && p.broker_notes && (
            <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-2xl p-4 mb-4 flex items-start gap-3">
              <span className="text-xl">⚠️</span>
              <div>
                <p className="text-sm font-bold text-amber-800 dark:text-amber-300">{lang === 'en' ? 'Changes Requested by Broker' : 'Cambios Solicitados por el Broker'}</p>
                <p className="text-sm text-amber-700 dark:text-amber-400 mt-1">{p.broker_notes}</p>
              </div>
            </div>
          )}

          {/* Header */}
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-4 mb-6">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <PropertyStatusBadge status={p.status} lang={lang} size="lg" />
                {typeLabel && <span className="text-xs font-semibold uppercase tracking-widest text-brand-500">{typeLabel}</span>}
                {daysOnMarket !== null && (
                  <span className="text-xs font-medium text-gray-400 dark:text-gray-500">
                    {daysOnMarket} {lang === 'en' ? 'days' : 'días'}
                  </span>
                )}
              </div>
              <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{title}</h1>
              {p.unparsed_address && (
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
                  {p.unparsed_address}
                </p>
              )}
              <p className="text-3xl font-black text-gray-900 dark:text-white mt-2">
                {formatPrice(p.list_price, p.list_price_currency_id)}
              </p>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 flex-shrink-0">
              {canEdit && (
                <button onClick={() => router.push(`/propiedades/nueva?edit=${p.id}`)} className="px-4 py-2 rounded-xl border border-gray-200 dark:border-dark-border bg-white dark:bg-dark-panel hover:bg-slate-50 dark:hover:bg-white/5 text-sm font-medium text-gray-700 dark:text-white transition-colors">
                  ✏️ {lang === 'en' ? 'Edit' : 'Editar'}
                </button>
              )}
              {canEdit && (
                <button onClick={() => updateStatus('pending_approval')} disabled={actionLoading} className="px-4 py-2 rounded-xl bg-brand-500 hover:bg-brand-600 text-white text-sm font-semibold shadow-md shadow-brand-500/20 transition-all disabled:opacity-50">
                  {lang === 'en' ? 'Submit for Approval' : 'Enviar para Aprobación'}
                </button>
              )}
              {p.status === 'approved' && (
                <span className="px-4 py-2 rounded-xl bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400 text-sm font-semibold border border-green-200 dark:border-green-800">
                  ✅ {lang === 'en' ? 'Approved — Ready to Publish' : 'Aprobada — Lista para Publicar'}
                </span>
              )}
              {(p.status === 'published' || p.status === 'approved') && p.status !== 'sold' && (
                <button
                  onClick={() => setShowSoldModal(true)}
                  className="px-4 py-2 rounded-xl bg-emerald-500 hover:bg-emerald-600 text-white text-sm font-semibold shadow-md shadow-emerald-500/20 transition-all flex items-center gap-1.5"
                >
                  🎉 {lang === 'en' ? 'Mark as Sold' : 'Marcar como Vendida'}
                </button>
              )}
              {p.status === 'sold' && (
                <span className="px-4 py-2 rounded-xl bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 text-sm font-bold border border-emerald-200 dark:border-emerald-800">
                  🏆 {lang === 'en' ? 'SOLD' : 'VENDIDA'} — {p.sold_price ? formatPrice(p.sold_price, p.list_price_currency_id) : ''}
                </span>
              )}
            </div>
          </div>

          {/* Property Timeline */}
          <PropertyTimeline milestones={milestones} t={t} lang={lang} />

          {/* Photo Gallery */}
          <div className="glass-panel rounded-2xl overflow-hidden mb-4">
            {images.length > 0 ? (
              <>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-1">
                  {images.slice(0, 8).map((img, i) => (
                    <div key={img.id} className={`relative group ${i === 0 ? 'col-span-2 row-span-2' : ''}`}>
                      <img src={img.image_url} alt="" className="w-full h-full object-cover aspect-square" />
                      <button
                        onClick={() => handleDeleteImage(img.id)}
                        className="absolute top-2 right-2 w-7 h-7 rounded-full bg-black/50 text-white text-xs flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"
                      >
                        ✕
                      </button>
                    </div>
                  ))}
                </div>
                {images.length > 8 && (
                  <p className="text-center py-2 text-xs text-gray-500">+{images.length - 8} {lang === 'en' ? 'more photos' : 'fotos más'}</p>
                )}
              </>
            ) : (
              <div className="p-8 text-center">
                <svg className="w-10 h-10 text-gray-300 dark:text-gray-600 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-2">{lang === 'en' ? 'No photos yet' : 'Aún no hay fotos'}</p>
              </div>
            )}

            {/* Photo actions bar */}
            <div className="flex items-center justify-between gap-2 px-4 py-3 border-t border-gray-100 dark:border-dark-border bg-gray-50/50 dark:bg-white/5">
              <p className="text-xs text-gray-500 dark:text-gray-400">
                🖼️ {images.length} {lang === 'en' ? 'photos' : 'fotos'}
                {p.photos_ready && <span className="text-green-500 ml-2">✓ {lang === 'en' ? 'Ready' : 'Listas'}</span>}
              </p>
              <div className="flex items-center gap-2">
                {!p.drive_photos_folder_id ? (
                  <button
                    onClick={handleCreateFolder}
                    disabled={creatingFolder}
                    className="px-3 py-1.5 rounded-lg bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 text-xs font-semibold hover:bg-blue-100 dark:hover:bg-blue-900/30 transition-colors disabled:opacity-50 flex items-center gap-1.5"
                  >
                    {creatingFolder ? (
                      <div className="w-3 h-3 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
                    ) : (
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z" /></svg>
                    )}
                    {lang === 'en' ? 'Create Drive Folder' : 'Crear Carpeta Drive'}
                  </button>
                ) : (
                  <>
                    <a
                      href={p.drive_photos_folder_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="px-3 py-1.5 rounded-lg bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 text-xs font-semibold hover:bg-blue-100 dark:hover:bg-blue-900/30 transition-colors flex items-center gap-1.5"
                    >
                      <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="currentColor"><path d="M7.71 3.5L1.15 15l4.58 7.5h13.54l4.58-7.5L17.29 3.5H7.71z" /></svg>
                      {lang === 'en' ? 'Open Drive' : 'Abrir Drive'}
                    </a>
                    <button
                      onClick={handleSyncPhotos}
                      disabled={syncingPhotos}
                      className="px-3 py-1.5 rounded-lg bg-brand-50 dark:bg-brand-900/20 text-brand-600 dark:text-brand-400 text-xs font-semibold hover:bg-brand-100 dark:hover:bg-brand-900/30 transition-colors disabled:opacity-50 flex items-center gap-1.5"
                    >
                      {syncingPhotos ? (
                        <div className="w-3 h-3 border-2 border-brand-500 border-t-transparent rounded-full animate-spin" />
                      ) : (
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                      )}
                      {lang === 'en' ? 'Sync Photos' : 'Sincronizar Fotos'}
                    </button>
                  </>
                )}
              </div>
            </div>
          </div>

          {/* Content Grid */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            {/* Left Column */}
            <div className="lg:col-span-2 space-y-4">
              {/* Description */}
              {(p.public_remarks_es || p.public_remarks_en) && (
                <SectionCard title={lang === 'en' ? 'Description' : 'Descripción'} icon="📝">
                  <p className="text-sm text-gray-700 dark:text-gray-300 whitespace-pre-wrap">
                    {lang === 'en' ? (p.public_remarks_en || p.public_remarks_es) : (p.public_remarks_es || p.public_remarks_en)}
                  </p>
                </SectionCard>
              )}

              {/* Details */}
              <SectionCard title={lang === 'en' ? 'Property Details' : 'Detalles'} icon="📐">
                <InfoRow label={lang === 'en' ? 'Bedrooms' : 'Habitaciones'} value={p.bedrooms_total} />
                <InfoRow label={lang === 'en' ? 'Full Bathrooms' : 'Baños Completos'} value={p.bathrooms_full} />
                <InfoRow label={lang === 'en' ? 'Half Bathrooms' : 'Medios Baños'} value={p.bathrooms_half} />
                <InfoRow label={lang === 'en' ? 'Floors' : 'Pisos'} value={p.stories} />
                <InfoRow label={lang === 'en' ? 'Lot Size' : 'Terreno'} value={p.lot_size_area ? `${Number(p.lot_size_area).toLocaleString()} m²` : null} />
                <InfoRow label={lang === 'en' ? 'Construction' : 'Construcción'} value={p.construction_size ? `${Number(p.construction_size).toLocaleString()} m²` : null} />
                <InfoRow label={lang === 'en' ? 'Year Built' : 'Año'} value={p.year_built} />
                <InfoRow label={lang === 'en' ? 'Garage Spaces' : 'Espacios Garaje'} value={p.garage ? p.garage_spaces : null} />
              </SectionCard>

              {/* Amenities */}
              {amenities.length > 0 && (
                <SectionCard title={lang === 'en' ? 'Amenities' : 'Amenidades'} icon="✨">
                  <div className="flex flex-wrap gap-2">
                    {amenities.map(a => (
                      <span key={a} className="px-3 py-1 rounded-full bg-brand-50 dark:bg-brand-900/20 text-brand-600 dark:text-brand-400 text-xs font-semibold">
                        ✓ {a}
                      </span>
                    ))}
                  </div>
                </SectionCard>
              )}
            </div>

            {/* Right Column */}
            <div className="space-y-4">
              {/* Owner Info */}
              <SectionCard title={lang === 'en' ? 'Owner' : 'Propietario'} icon="👤">
                <InfoRow label={lang === 'en' ? 'Name' : 'Nombre'} value={p.owner_name} />
                <InfoRow label={lang === 'en' ? 'Phone' : 'Teléfono'} value={p.owner_phones} />
                <InfoRow label={lang === 'en' ? 'Email' : 'Email'} value={p.owner_email} />
                <InfoRow label={lang === 'en' ? 'Agreement' : 'Contrato'} value={p.listing_agreement ? '✅ Firmado' : '❌ Pendiente'} />
              </SectionCard>

              {/* Commission */}
              <SectionCard title={lang === 'en' ? 'Commission' : 'Comisión'} icon="💰">
                <InfoRow label="Listing Side" value={p.listing_side_comm ? `${p.listing_side_comm}%` : null} />
                <InfoRow label="Selling Side" value={p.selling_side_comm ? `${p.selling_side_comm}%` : null} />
                <InfoRow label="Total" value={(p.listing_side_comm && p.selling_side_comm) ? `${Number(p.listing_side_comm) + Number(p.selling_side_comm)}%` : null} />
              </SectionCard>

              {/* Syndication Panel */}
              <SectionCard title={lang === 'en' ? 'Portals' : 'Portales'} icon="🔗">
                <SyndicationPanel
                  propertyId={p.id}
                  propertyStatus={p.status}
                  onPublish={() => fetchProperty()}
                />
              </SectionCard>

              {/* Office */}
              <SectionCard title={lang === 'en' ? 'Office' : 'Oficina'} icon="🏢">
                <InfoRow label={lang === 'en' ? 'Office Code' : 'Código'} value={p.office_code} />
                <InfoRow label="RECONNECT ID" value={p.reconnect_listing_id} />
                <InfoRow label="Finca" value={p.finca_number} />
                <InfoRow label="Plano" value={p.plano_number} />
                {p.reconnect_last_sync && (
                  <InfoRow
                    label={lang === 'en' ? 'Last Sync' : 'Última Sync'}
                    value={new Date(p.reconnect_last_sync).toLocaleDateString()}
                  />
                )}
              </SectionCard>

              {/* Video */}
              {p.video_link && (
                <SectionCard title="Video" icon="🎬">
                  <a href={p.video_link} target="_blank" rel="noopener noreferrer" className="text-sm text-brand-500 hover:underline break-all">
                    {p.video_link}
                  </a>
                </SectionCard>
              )}

              {/* Analytics */}
              <SectionCard title={lang === 'en' ? 'Analytics' : 'Analíticas'} icon="📊">
                <ListingAnalyticsPanel propertyId={p.id} />
              </SectionCard>
            </div>
          </div>

        </div>
      </div>

      {/* ═══ MARK AS SOLD MODAL ═══ */}
      {showSoldModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4" onClick={() => setShowSoldModal(false)}>
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" />
          <div
            className="relative bg-white dark:bg-slate-800 rounded-[32px] shadow-2xl border border-slate-200 dark:border-slate-700 w-full max-w-2xl max-h-[90vh] overflow-y-auto p-6 md:p-8"
            onClick={e => e.stopPropagation()}
          >
            <div className="flex items-center justify-between mb-6">
              <div>
                <h3 className="text-xl font-black italic text-slate-900 dark:text-white">
                  🎉 {lang === 'en' ? 'Record Sale' : 'Registrar Venta'}
                </h3>
                <p className="text-xs text-slate-400 mt-1">{title}</p>
              </div>
              <button onClick={() => setShowSoldModal(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-white p-1">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <CommissionCalculator
              property={p}
              agentProfile={profile}
              onConfirm={(result) => {
                setShowSoldModal(false);
                setSoldResult(result);
                setShowCongratsModal(true);
                fetchProperty();
              }}
              onCancel={() => setShowSoldModal(false)}
            />
          </div>
        </div>
      )}

      {/* ═══ CONGRATS MODAL ═══ */}
      <SoldCongratsModal
        isOpen={showCongratsModal}
        onClose={() => {
          setShowCongratsModal(false);
          setSoldResult(null);
        }}
        propertyTitle={title}
        agentAmount={soldResult?.agentAmount}
        officeAmount={soldResult?.officeAmount}
        grossCommission={soldResult?.grossCommission}
        closingDate={soldResult?.closingDate}
        buyerName={soldResult?.buyerName}
        lang={lang}
      />
    </>
  );
}

