import { useAuth } from '@/lib/auth-context';
import OlympiaCoach from '@/components/olympia/OlympiaCoach';
import Link from 'next/link';

export default function TopNav({ titleKey, subtitleKey, title, subtitle }) {
  const { t, lang, toggleLang, toggleTheme } = useApp();
  const { profile, supabase } = useAuth();

  const [notifications, setNotifications] = useState([]);
  const [showNotifications, setShowNotifications] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    if (profile) {
      loadNotifications();
    }
  }, [profile]);

  useEffect(() => {
    // Close notifications on outside click
    const handleClickOutside = (event) => {
      if (notifRef.current && !notifRef.current.contains(event.target)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const loadNotifications = async () => {
    try {
      const { data } = await supabase
        .from('notifications')
        .select('*')
        .eq('user_id', profile.id)
        .order('created_at', { ascending: false })
        .limit(10);
      setNotifications(data || []);
    } catch (err) {
      console.error(err);
    }
  };

  const markAsRead = async (id) => {
    try {
      await supabase.from('notifications').update({ is_read: true }).eq('id', id);
      setNotifications(notifications.map(n => n.id === id ? { ...n, is_read: true } : n));
    } catch (err) {
      console.error(err);
    }
  };

  const unreadCount = notifications.filter(n => !n.is_read).length;

  const displayTitle    = titleKey    ? t(titleKey)    : title;
  const displaySubtitle = subtitleKey ? t(subtitleKey) : subtitle;

  return (
    <>
      <header className="h-16 md:h-20 glass-panel border-b border-gray-200 dark:border-dark-border flex items-center justify-between px-4 md:px-8 z-10 transition-colors shrink-0 shadow-xs dark:shadow-none">
        <div className="min-w-0 flex-1 mr-3">
          <h2 className="text-base md:text-xl font-bold text-gray-900 dark:text-white tracking-wide truncate">{displayTitle}</h2>
          <p className="text-[10px] md:text-xs text-gray-500 dark:text-gray-400 mt-0.5 tracking-wide truncate">{displaySubtitle}</p>
        </div>

        <div className="flex items-center space-x-2 md:space-x-3 shrink-0">
          {/* Search — hidden on small */}
          <div className="relative hidden lg:block">
            <svg className="w-4 h-4 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 dark:text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            <input type="text" placeholder={t('search_placeholder')} className="bg-white dark:bg-dark-bg border border-gray-300 dark:border-dark-border text-xs rounded-full pl-9 pr-4 py-2 w-64 focus:outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 text-gray-800 dark:text-gray-300 placeholder-gray-400 transition-all shadow-sm" />
          </div>

          {/* Notifications */}
          <div className="relative" ref={notifRef}>
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="relative w-8 h-8 md:w-9 md:h-9 rounded-full bg-white dark:bg-dark-bg border border-gray-300 dark:border-dark-border flex items-center justify-center text-gray-600 dark:text-gray-400 hover:text-brand-500 dark:hover:text-brand-400 transition-colors shadow-sm" 
              title="Notificaciones"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9"></path></svg>
              {unreadCount > 0 && (
                <span className="absolute top-0 right-0 flex h-2.5 w-2.5">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500 border border-white dark:border-dark-bg"></span>
                </span>
              )}
            </button>

            {showNotifications && (
              <div className="absolute right-0 mt-2 w-80 bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden z-50">
                <div className="p-4 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center">
                  <h3 className="text-sm font-bold text-slate-900 dark:text-white">Notificaciones</h3>
                  {unreadCount > 0 && <span className="text-[10px] bg-red-100 text-red-600 px-2 py-0.5 rounded font-black">{unreadCount} nuevas</span>}
                </div>
                <div className="max-h-80 overflow-y-auto divide-y divide-slate-100 dark:divide-slate-700/50">
                  {notifications.length === 0 ? (
                    <div className="p-6 text-center text-xs text-slate-400">No tienes notificaciones.</div>
                  ) : notifications.map(n => (
                    <div key={n.id} onClick={() => markAsRead(n.id)} className={`p-4 hover:bg-slate-50 dark:hover:bg-white/5 cursor-pointer transition-colors ${!n.is_read ? 'bg-blue-50/50 dark:bg-blue-900/10' : ''}`}>
                      <Link href={n.link || '#'} onClick={() => setShowNotifications(false)}>
                        <h4 className={`text-xs mb-1 ${!n.is_read ? 'font-bold text-slate-900 dark:text-white' : 'font-medium text-slate-700 dark:text-slate-300'}`}>{n.title}</h4>
                        <p className="text-[10px] text-slate-500 leading-tight">{n.message}</p>
                        <p className="text-[9px] text-slate-400 mt-2">{new Date(n.created_at).toLocaleString()}</p>
                      </Link>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Language Toggle */}
          <button onClick={toggleLang} className="w-11 md:w-14 h-8 md:h-9 rounded-full bg-white dark:bg-dark-bg border border-gray-300 dark:border-dark-border flex items-center justify-center text-xs font-bold text-gray-600 dark:text-gray-400 hover:text-brand-500 dark:hover:text-white transition-colors shadow-sm">
            <span>{lang === 'es' ? 'EN' : 'ES'}</span>
          </button>

          {/* Theme Toggle */}
          <button onClick={toggleTheme} className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-white dark:bg-dark-bg border border-gray-300 dark:border-dark-border flex items-center justify-center text-gray-600 dark:text-gray-400 hover:text-brand-500 dark:hover:text-white transition-colors shadow-sm">
            <svg className="w-4 h-4 hidden dark:block" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
            <svg className="w-4 h-4 block dark:hidden" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z"></path></svg>
          </button>
        </div>
      </header>
      <OlympiaCoach />
    </>
  );
}

"use client";

import { useState, useEffect, useMemo } from 'react';
import { useApp } from '@/lib/context';
import { useAuth } from '@/lib/auth-context';
import { supabase } from '@/lib/supabase';

/* ═══════════════════════════════════════════════════════════════
   AGENT COMMISSIONS PANEL
   Shows YTD summary, current tier, commission history table
   with expandable breakdowns, and monthly trend chart.
   ═══════════════════════════════════════════════════════════════ */

const MONTH_NAMES_ES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const MONTH_NAMES_EN = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

const STATUS_STYLES = {
  pending:    'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-500/10 dark:text-amber-400 dark:border-amber-500/20',
  processing: 'bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-500/10 dark:text-blue-400 dark:border-blue-500/20',
  paid:       'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-500/10 dark:text-emerald-400 dark:border-emerald-500/20',
  partial:    'bg-purple-50 text-purple-700 border-purple-200 dark:bg-purple-500/10 dark:text-purple-400 dark:border-purple-500/20',
};

function MiniBarChart({ data, labels, color = 'bg-emerald-500' }) {
  const max = Math.max(...data, 1);
  return (
    <div className="flex items-end gap-1.5 h-28">
      {data.map((val, i) => (
        <div key={i} className="flex-1 flex flex-col items-center gap-1">
          <span className="text-[9px] font-bold text-slate-500 tabular-nums">
            {val > 0 ? `$${(val / 1000).toFixed(0)}k` : '—'}
          </span>
          <div className="w-full bg-slate-100 dark:bg-slate-700/50 rounded-t-md overflow-hidden flex-1 flex items-end">
            <div
              className={`w-full ${color} rounded-t-md transition-all duration-700 ease-out opacity-85 hover:opacity-100`}
              style={{ height: `${Math.max((val / max) * 100, 4)}%` }}
            />
          </div>
          <span className="text-[8px] font-bold text-slate-400 uppercase">{labels[i]}</span>
        </div>
      ))}
    </div>
  );
}

export default function AgentCommissionsPanel({ initialCommissions = [], initialTiers = [] }) {
  const { t, lang } = useApp();
  const { profile } = useAuth();
  const [commissions, setCommissions] = useState(initialCommissions);
  const [tiers, setTiers] = useState(initialTiers);
  const [loading, setLoading] = useState(initialCommissions.length === 0);
  const [expandedId, setExpandedId] = useState(null);

  // Load data client-side if not from SSR
  useEffect(() => {
    if (initialCommissions.length > 0 && initialTiers.length > 0) return;
    if (!profile?.id) return;

    const loadData = async () => {
      setLoading(true);
      try {
        const [{ data: c }, { data: t }] = await Promise.all([
          supabase
            .from('agent_commissions')
            .select('*, properties(name, listing_title_es, listing_title_en, unparsed_address)')
            .eq('agent_id', profile.id)
            .order('closing_date', { ascending: false }),
          supabase
            .from('commission_tiers')
            .select('*')
            .eq('active', true)
            .order('sort_order'),
        ]);
        if (c) setCommissions(c);
        if (t) setTiers(t);
      } catch (err) {
        console.error('CommissionsPanel load error:', err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, [profile?.id, initialCommissions.length, initialTiers.length]);

  const fmt = (n) => '$' + Number(n || 0).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

  // ── Stats ──
  const now = new Date();
  const yearStart = `${now.getFullYear()}-01-01`;
  const ytdCommissions = commissions.filter(c => c.closing_date >= yearStart);

  const earned = ytdCommissions
    .filter(c => c.status === 'paid')
    .reduce((s, c) => s + (Number(c.agent_amount) || 0), 0);

  const pending = ytdCommissions
    .filter(c => c.status === 'pending' || c.status === 'processing')
    .reduce((s, c) => s + (Number(c.agent_amount) || 0), 0);

  const totalClosings = ytdCommissions.length;
  const avgPerClose = totalClosings > 0
    ? ytdCommissions.reduce((s, c) => s + (Number(c.agent_amount) || 0), 0) / totalClosings
    : 0;

  // ── Agent's current tier ──
  const agentTier = tiers.find(t => t.id === profile?.commission_tier_id) || tiers.find(t => t.name === 'starter');

  // ── Monthly Trend (last 6 months) ──
  const monthLabels = lang === 'es' ? MONTH_NAMES_ES : MONTH_NAMES_EN;
  const monthlyTrend = useMemo(() => {
    const data = [];
    const labels = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const monthStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      const total = commissions
        .filter(c => c.closing_date?.startsWith(monthStr) && c.status === 'paid')
        .reduce((s, c) => s + (Number(c.agent_amount) || 0), 0);
      data.push(total);
      labels.push(monthLabels[d.getMonth()]);
    }
    return { data, labels };
  }, [commissions, monthLabels]);

  if (loading) {
    return (
      <div className="flex justify-center py-20">
        <div className="animate-spin w-8 h-8 border-2 border-emerald-500 border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* ── Summary Cards ── */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: t('comm_ytd_earned'), value: fmt(earned), color: 'text-emerald-600 dark:text-emerald-400', icon: '💰' },
          { label: t('comm_pending'), value: fmt(pending), color: 'text-amber-600 dark:text-amber-400', icon: '⏳' },
          { label: t('comm_total_closings'), value: totalClosings, color: 'text-slate-900 dark:text-white', icon: '📊' },
          { label: t('comm_avg_per_close'), value: fmt(avgPerClose), color: 'text-blue-600 dark:text-blue-400', icon: '📈' },
        ].map((s, i) => (
          <div key={i} className="bg-white dark:bg-slate-800/50 rounded-2xl p-5 border border-slate-200 dark:border-white/10 shadow-sm relative overflow-hidden group hover:shadow-lg hover:scale-[1.02] transition-all duration-300">
            <div className="absolute top-3 right-3 text-2xl opacity-20 group-hover:opacity-40 transition-opacity">{s.icon}</div>
            <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest leading-none">{s.label}</p>
            <h3 className={`text-2xl font-black italic mt-2 ${s.color} tabular-nums`}>{s.value}</h3>
          </div>
        ))}
      </div>

      {/* ── Current Tier Card ── */}
      {agentTier && (
        <div className="bg-gradient-to-br from-slate-900 to-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700/50 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-5">
            <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-emerald-500/20 to-teal-500/20 border border-emerald-500/30 flex items-center justify-center">
              <span className="text-3xl font-black text-emerald-400">{agentTier.agent_split_pct}%</span>
            </div>
            <div>
              <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{t('comm_your_tier')}</p>
              <h3 className="text-xl font-black text-white capitalize mt-0.5">{lang === 'en' ? agentTier.label_en : agentTier.label_es}</h3>
              <p className="text-xs text-slate-400 mt-1">
                {t('comm_monthly_fee')}: ${agentTier.monthly_fee_usd} {t('comm_plus_iva')} · {t('comm_your_split')}: {agentTier.agent_split_pct}%
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            {tiers.map(tier => (
              <div
                key={tier.id}
                className={`px-3 py-2 rounded-xl text-center border transition-all ${
                  tier.id === agentTier.id
                    ? 'bg-emerald-500/20 border-emerald-500/40 text-emerald-400'
                    : 'bg-white/5 border-white/10 text-slate-500'
                }`}
              >
                <p className="text-lg font-black">{tier.agent_split_pct}%</p>
                <p className="text-[8px] uppercase tracking-widest font-bold mt-0.5">{tier.name}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Monthly Trend ── */}
      {monthlyTrend.data.some(v => v > 0) && (
        <div className="bg-white dark:bg-slate-800/50 rounded-2xl p-5 border border-slate-200 dark:border-white/10 shadow-sm">
          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z" /></svg>
            {t('comm_trend_title')} — {t('comm_paid')}
          </h4>
          <MiniBarChart data={monthlyTrend.data} labels={monthlyTrend.labels} />
        </div>
      )}

      {/* ── Commission History Table ── */}
      <div className="bg-white dark:bg-slate-800/50 rounded-2xl border border-slate-200 dark:border-white/10 shadow-sm overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 dark:border-white/10 bg-slate-50/50 dark:bg-slate-900/50">
          <h3 className="text-sm font-black text-slate-900 dark:text-white flex items-center gap-2">
            💰 {t('comm_history_title')}
          </h3>
        </div>

        {commissions.length === 0 ? (
          <div className="p-12 text-center">
            <div className="text-5xl mb-4 opacity-30">💰</div>
            <h3 className="text-lg font-bold text-slate-500 dark:text-slate-400 mb-2">{t('comm_no_commissions')}</h3>
            <p className="text-sm text-slate-400 max-w-sm mx-auto">{t('comm_no_commissions_desc')}</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse min-w-[700px]">
              <thead>
                <tr className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-white/10">
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{t('comm_date')}</th>
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{t('comm_property')}</th>
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{t('comm_sale_price')}</th>
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{t('comm_side')}</th>
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{t('comm_split')}</th>
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">{t('comm_agent_amount')}</th>
                  <th className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{t('comm_status')}</th>
                  <th className="px-4 py-3"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-white/5">
                {commissions.map(c => {
                  const propTitle = c.properties
                    ? (lang === 'en' ? c.properties.listing_title_en : c.properties.listing_title_es) || c.properties.name || c.properties.unparsed_address
                    : '—';
                  const isExpanded = expandedId === c.id;
                  const sideLabel = c.side === 'listing' ? (lang === 'en' ? 'Listing' : 'Captación')
                    : c.side === 'selling' ? (lang === 'en' ? 'Selling' : 'Venta')
                    : (lang === 'en' ? 'Both' : 'Ambos');
                  const statusKey = `comm_status_${c.status}`;

                  return (
                    <>
                      <tr key={c.id} className="hover:bg-slate-50 dark:hover:bg-white/5 transition-colors">
                        <td className="px-4 py-3.5 text-xs text-slate-500 font-medium whitespace-nowrap">
                          {c.closing_date ? new Date(c.closing_date + 'T12:00:00').toLocaleDateString(lang === 'es' ? 'es-CR' : 'en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '—'}
                        </td>
                        <td className="px-4 py-3.5">
                          <p className="text-sm font-semibold text-slate-900 dark:text-white truncate max-w-[180px]">{propTitle}</p>
                        </td>
                        <td className="px-4 py-3.5 text-sm font-medium text-slate-900 dark:text-white tabular-nums">{fmt(c.sale_price)}</td>
                        <td className="px-4 py-3.5">
                          <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">{sideLabel}</span>
                        </td>
                        <td className="px-4 py-3.5">
                          <span className="text-xs font-bold text-slate-700 dark:text-slate-300">{c.agent_split_pct}%</span>
                        </td>
                        <td className="px-4 py-3.5 text-right">
                          <span className="text-base font-black text-emerald-600 dark:text-emerald-400 tabular-nums">{fmt(c.agent_amount)}</span>
                        </td>
                        <td className="px-4 py-3.5">
                          <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-[10px] font-bold border ${STATUS_STYLES[c.status] || STATUS_STYLES.pending}`}>
                            {t(statusKey)}
                          </span>
                        </td>
                        <td className="px-4 py-3.5">
                          <button
                            onClick={() => setExpandedId(isExpanded ? null : c.id)}
                            className="text-[10px] font-bold text-brand-600 dark:text-brand-400 hover:underline uppercase tracking-widest"
                          >
                            {isExpanded ? '▲' : t('comm_breakdown')}
                          </button>
                        </td>
                      </tr>
                      {isExpanded && (
                        <tr key={`${c.id}-detail`}>
                          <td colSpan="8" className="px-6 py-4 bg-slate-50 dark:bg-slate-900/50">
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                              <div>
                                <p className="text-[9px] text-slate-400 uppercase font-bold tracking-widest mb-1">{t('comm_gross')}</p>
                                <p className="font-bold text-slate-900 dark:text-white">{fmt(c.gross_commission)}</p>
                                <p className="text-[10px] text-slate-400">{c.total_commission_pct}% {lang === 'en' ? 'of sale' : 'de la venta'}</p>
                              </div>
                              <div>
                                <p className="text-[9px] text-slate-400 uppercase font-bold tracking-widest mb-1">{t('comm_side_amount')}</p>
                                <p className="font-bold text-slate-900 dark:text-white">{fmt(c.side_amount)}</p>
                                <p className="text-[10px] text-slate-400">{c.side_pct}% {lang === 'en' ? 'of gross' : 'del bruto'}</p>
                              </div>
                              <div>
                                <p className="text-[9px] text-red-400 uppercase font-bold tracking-widest mb-1">{t('comm_rcca')}</p>
                                <p className="font-bold text-red-500">-{fmt(c.rcca_fee_amount)}</p>
                                <p className="text-[10px] text-slate-400">{c.rcca_fee_pct}%</p>
                              </div>
                              <div>
                                <p className="text-[9px] text-blue-400 uppercase font-bold tracking-widest mb-1">{t('comm_office')}</p>
                                <p className="font-bold text-blue-500">{fmt(c.office_amount)}</p>
                                <p className="text-[10px] text-slate-400">{Math.round(100 - c.agent_split_pct)}%</p>
                              </div>
                              {c.referral_pct > 0 && (
                                <div>
                                  <p className="text-[9px] text-amber-400 uppercase font-bold tracking-widest mb-1">{t('comm_referral')}</p>
                                  <p className="font-bold text-amber-500">-{fmt(c.referral_amount)}</p>
                                  <p className="text-[10px] text-slate-400">{c.referral_pct}% → {c.referral_agent || '—'}</p>
                                </div>
                              )}
                            </div>
                          </td>
                        </tr>
                      )}
                    </>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useMemo } from 'react';
import { useApp } from '@/lib/context';
import { useAuth } from '@/lib/auth-context';
import { supabase } from '@/lib/supabase';

/* ═══════════════════════════════════════════════════════════════
   AGENT REFERRALS PANEL
   Shows referrals sent/received by the agent, with create modal.
   Fee is configurable (default 25%) on the gross side amount.
   ═══════════════════════════════════════════════════════════════ */

const STATUS_STYLES = {
  pending:   'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-500/10 dark:text-amber-400 dark:border-amber-500/20',
  active:    'bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-500/10 dark:text-blue-400 dark:border-blue-500/20',
  closed:    'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-500/10 dark:text-emerald-400 dark:border-emerald-500/20',
  paid:      'bg-green-50 text-green-700 border-green-200 dark:bg-green-500/10 dark:text-green-400 dark:border-green-500/20',
  cancelled: 'bg-red-50 text-red-700 border-red-200 dark:bg-red-500/10 dark:text-red-400 dark:border-red-500/20',
};

const DIRECTION_ICONS = { sent: '📤', received: '📥' };

export default function AgentReferralsPanel({ initialReferrals = [] }) {
  const { t, lang } = useApp();
  const { profile } = useAuth();
  const [referrals, setReferrals] = useState(initialReferrals);
  const [loading, setLoading] = useState(initialReferrals.length === 0);
  const [showModal, setShowModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [filter, setFilter] = useState('all');

  const fmt = (n) => '$' + Number(n || 0).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

  const [form, setForm] = useState({
    direction: 'sent',
    referring_agent_name: '',
    referring_office: '',
    receiving_agent_name: '',
    receiving_office: '',
    client_name: '',
    client_email: '',
    client_phone: '',
    property_address: '',
    referral_fee_pct: 25,
    notes: '',
  });

  // Load referrals client-side if not from SSR
  useEffect(() => {
    if (initialReferrals.length > 0 || !profile?.id) return;
    const load = async () => {
      setLoading(true);
      try {
        const { data } = await supabase
          .from('agent_referrals')
          .select('*, referring_profile:profiles!agent_referrals_referring_agent_id_fkey(full_name, avatar_url, office), receiving_profile:profiles!agent_referrals_receiving_agent_id_fkey(full_name, avatar_url, office)')
          .or(`referring_agent_id.eq.${profile.id},receiving_agent_id.eq.${profile.id}`)
          .order('created_at', { ascending: false });
        if (data) setReferrals(data);
      } catch (err) {
        console.error('Referrals load:', err);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [profile?.id, initialReferrals.length]);

  // Stats
  const sent = referrals.filter(r => r.referring_agent_id === profile?.id);
  const received = referrals.filter(r => r.receiving_agent_id === profile?.id);
  const feesToCollect = sent.filter(r => r.status === 'closed').reduce((s, r) => s + (Number(r.referral_fee_amount) || 0), 0);
  const feesToPay = received.filter(r => r.status === 'closed').reduce((s, r) => s + (Number(r.referral_fee_amount) || 0), 0);

  // Filtered
  const filtered = useMemo(() => {
    if (filter === 'sent') return sent;
    if (filter === 'received') return received;
    return referrals;
  }, [referrals, filter, profile?.id]);

  // Determine direction label for a referral row
  const getDirection = (r) => r.referring_agent_id === profile?.id ? 'sent' : 'received';

  // Create referral
  const handleCreate = async () => {
    if (!form.client_name) return;
    setSaving(true);
    try {
      const isSent = form.direction === 'sent';
      const payload = {
        direction: form.direction,
        referring_agent_id: isSent ? profile.id : null,
        referring_agent_name: isSent ? profile.full_name : form.referring_agent_name,
        referring_office: isSent ? (profile.office || 'altitud') : form.referring_office,
        receiving_agent_id: isSent ? null : profile.id,
        receiving_agent_name: isSent ? form.receiving_agent_name : profile.full_name,
        receiving_office: isSent ? form.receiving_office : (profile.office || 'altitud'),
        client_name: form.client_name,
        client_email: form.client_email,
        client_phone: form.client_phone,
        property_address: form.property_address,
        referral_fee_pct: Number(form.referral_fee_pct) || 25,
        notes: form.notes,
        status: 'pending',
      };
      const { data, error } = await supabase.from('agent_referrals').insert([payload]).select('*, referring_profile:profiles!agent_referrals_referring_agent_id_fkey(full_name, avatar_url, office), receiving_profile:profiles!agent_referrals_receiving_agent_id_fkey(full_name, avatar_url, office)');
      if (error) throw error;
      if (data) setReferrals(prev => [data[0], ...prev]);
      setShowModal(false);
      setForm({ direction: 'sent', referring_agent_name: '', referring_office: '', receiving_agent_name: '', receiving_office: '', client_name: '', client_email: '', client_phone: '', property_address: '', referral_fee_pct: 25, notes: '' });
    } catch (err) {
      console.error('Create referral error:', err);
      alert('Error: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  // Update status
  const updateStatus = async (id, newStatus) => {
    const updates = { status: newStatus };
    if (newStatus === 'paid') updates.payment_date = new Date().toISOString().slice(0, 10);
    const { error } = await supabase.from('agent_referrals').update(updates).eq('id', id);
    if (!error) setReferrals(prev => prev.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  if (loading) {
    return <div className="flex justify-center py-20"><div className="animate-spin w-8 h-8 border-2 border-brand-500 border-t-transparent rounded-full" /></div>;
  }

  return (
    <div className="space-y-8">

      {/* ── Summary Cards ── */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: t('ref_total_sent'), val: sent.length, color: 'text-blue-600 dark:text-blue-400', icon: '📤' },
          { label: t('ref_total_received'), val: received.length, color: 'text-purple-600 dark:text-purple-400', icon: '📥' },
          { label: t('ref_fee_owed'), val: fmt(feesToCollect), color: 'text-emerald-600 dark:text-emerald-400', icon: '💰' },
          { label: t('ref_fee_to_pay'), val: fmt(feesToPay), color: 'text-amber-600 dark:text-amber-400', icon: '💸' },
        ].map((s, i) => (
          <div key={i} className="bg-white dark:bg-slate-800/50 rounded-2xl p-5 border border-slate-200 dark:border-white/10 shadow-sm relative overflow-hidden group hover:shadow-lg hover:scale-[1.02] transition-all duration-300">
            <div className="absolute top-3 right-3 text-2xl opacity-20 group-hover:opacity-40 transition-opacity">{s.icon}</div>
            <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest leading-none">{s.label}</p>
            <h3 className={`text-2xl font-black italic mt-2 ${s.color} tabular-nums`}>{s.val}</h3>
          </div>
        ))}
      </div>

      {/* ── Filter + Create ── */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
        <div className="flex bg-white dark:bg-slate-800/50 rounded-2xl p-1 shadow-sm border border-slate-200 dark:border-white/10">
          {[
            { key: 'all', label: t('ref_filter_all') },
            { key: 'sent', label: t('ref_sent') },
            { key: 'received', label: t('ref_received') },
          ].map(f => (
            <button key={f.key} onClick={() => setFilter(f.key)}
              className={`px-4 py-2 rounded-xl text-[11px] font-bold uppercase tracking-widest transition-all ${filter === f.key ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/20' : 'text-slate-500 hover:text-slate-700 dark:hover:text-white'}`}>
              {f.label}
            </button>
          ))}
        </div>
        <button onClick={() => setShowModal(true)}
          className="bg-brand-600 hover:bg-brand-700 text-white px-5 py-2.5 rounded-xl text-[11px] font-black uppercase tracking-widest shadow-xl shadow-brand-500/20 transition-all flex items-center gap-2">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
          {t('ref_create')}
        </button>
      </div>

      {/* ── Referral List ── */}
      <div className="bg-white dark:bg-slate-800/50 rounded-2xl border border-slate-200 dark:border-white/10 shadow-sm overflow-hidden">
        {filtered.length === 0 ? (
          <div className="p-12 text-center">
            <div className="text-5xl mb-4 opacity-30">🔗</div>
            <h3 className="text-lg font-bold text-slate-500 dark:text-slate-400 mb-2">{t('ref_empty_title')}</h3>
            <p className="text-sm text-slate-400 max-w-sm mx-auto">{t('ref_empty_desc')}</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[700px]">
              <thead>
                <tr className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-white/10">
                  {[t('ref_direction'), t('ref_client'), t('ref_referring_agent'), t('ref_receiving_agent'), t('ref_fee_pct'), t('ref_fee_amount'), t('comm_status'), ''].map((h, i) => (
                    <th key={i} className="px-4 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-white/5">
                {filtered.map(r => {
                  const dir = getDirection(r);
                  const referringName = r.referring_profile?.full_name || r.referring_agent_name || '—';
                  const receivingName = r.receiving_profile?.full_name || r.receiving_agent_name || '—';
                  return (
                    <tr key={r.id} className="hover:bg-slate-50 dark:hover:bg-white/5 transition-colors">
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold border ${dir === 'sent' ? 'bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-500/10 dark:text-blue-400 dark:border-blue-500/20' : 'bg-purple-50 text-purple-700 border-purple-200 dark:bg-purple-500/10 dark:text-purple-400 dark:border-purple-500/20'}`}>
                          {DIRECTION_ICONS[dir]} {dir === 'sent' ? t('ref_sent') : t('ref_received')}
                        </span>
                      </td>
                      <td className="px-4 py-3.5">
                        <p className="text-sm font-semibold text-slate-900 dark:text-white">{r.client_name}</p>
                        {r.property_address && <p className="text-[10px] text-slate-400 truncate max-w-[150px]">{r.property_address}</p>}
                        {/* Referred by label */}
                        {dir === 'received' && (
                          <span className="inline-flex items-center gap-1 mt-1 px-2 py-0.5 rounded-full bg-amber-50 dark:bg-amber-500/10 text-amber-700 dark:text-amber-400 text-[9px] font-bold border border-amber-200 dark:border-amber-500/20">
                            🔗 {t('ref_referred_by')} {referringName}
                          </span>
                        )}
                      </td>
                      <td className="px-4 py-3.5">
                        <p className="text-sm font-medium text-slate-700 dark:text-slate-300">{referringName}</p>
                        <p className="text-[10px] text-slate-400">{r.referring_office || '—'}</p>
                      </td>
                      <td className="px-4 py-3.5">
                        <p className="text-sm font-medium text-slate-700 dark:text-slate-300">{receivingName}</p>
                        <p className="text-[10px] text-slate-400">{r.receiving_office || '—'}</p>
                      </td>
                      <td className="px-4 py-3.5 text-sm font-bold tabular-nums">{r.referral_fee_pct}%</td>
                      <td className="px-4 py-3.5 text-sm font-black text-emerald-600 dark:text-emerald-400 tabular-nums">
                        {r.referral_fee_amount > 0 ? fmt(r.referral_fee_amount) : '—'}
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex px-2.5 py-1 rounded-full text-[10px] font-bold border ${STATUS_STYLES[r.status] || STATUS_STYLES.pending}`}>
                          {t(`ref_status_${r.status}`)}
                        </span>
                      </td>
                      <td className="px-4 py-3.5">
                        <div className="flex gap-1 flex-col">
                          {r.status === 'pending' && (
                            <button onClick={() => updateStatus(r.id, 'active')} className="text-[9px] font-bold text-blue-600 hover:underline uppercase tracking-widest">{t('ref_mark_active')}</button>
                          )}
                          {r.status === 'active' && (
                            <button onClick={() => updateStatus(r.id, 'closed')} className="text-[9px] font-bold text-emerald-600 hover:underline uppercase tracking-widest">{t('ref_mark_closed')}</button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* ── Create Referral Modal ── */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4" onClick={() => setShowModal(false)}>
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" />
          <div className="relative bg-white dark:bg-slate-800 rounded-[32px] shadow-2xl border border-slate-200 dark:border-slate-700 w-full max-w-lg p-8 space-y-5 max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div>
              <h3 className="text-xl font-black italic text-slate-900 dark:text-white">{t('ref_create')}</h3>
              <p className="text-xs text-slate-400 mt-1">{t('ref_create_desc')}</p>
            </div>

            {/* Direction Toggle */}
            <div>
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">{t('ref_direction')}</label>
              <div className="flex gap-2">
                {[
                  { key: 'sent', label: t('ref_direction_sent'), icon: '📤' },
                  { key: 'received', label: t('ref_direction_received'), icon: '📥' },
                ].map(d => (
                  <button key={d.key} onClick={() => setForm(p => ({ ...p, direction: d.key }))}
                    className={`flex-1 py-3 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all border flex items-center justify-center gap-2 ${form.direction === d.key ? 'bg-brand-600 text-white border-brand-600' : 'bg-white dark:bg-slate-900 text-slate-500 border-slate-200 dark:border-slate-700'}`}>
                    <span>{d.icon}</span> {d.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Other agent info */}
            <div className="grid grid-cols-2 gap-3">
              <div className="col-span-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">
                  {form.direction === 'sent' ? t('ref_receiving_agent') : t('ref_referring_agent')}
                </label>
                <input type="text" placeholder={t('ref_agent_name')}
                  value={form.direction === 'sent' ? form.receiving_agent_name : form.referring_agent_name}
                  onChange={e => setForm(p => form.direction === 'sent' ? { ...p, receiving_agent_name: e.target.value } : { ...p, referring_agent_name: e.target.value })}
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
              </div>
              <div className="col-span-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_office_name')}</label>
                <input type="text" placeholder={t('ref_external_office')}
                  value={form.direction === 'sent' ? form.receiving_office : form.referring_office}
                  onChange={e => setForm(p => form.direction === 'sent' ? { ...p, receiving_office: e.target.value } : { ...p, referring_office: e.target.value })}
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
              </div>
            </div>

            {/* Client */}
            <div className="space-y-3">
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_client_name')} *</label>
                <input type="text" required value={form.client_name} onChange={e => setForm(p => ({ ...p, client_name: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_client_email')}</label>
                  <input type="email" value={form.client_email} onChange={e => setForm(p => ({ ...p, client_email: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_client_phone')}</label>
                  <input type="tel" value={form.client_phone} onChange={e => setForm(p => ({ ...p, client_phone: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
                </div>
              </div>
            </div>

            {/* Property + Fee */}
            <div className="space-y-3">
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_property_address')}</label>
                <input type="text" value={form.property_address} onChange={e => setForm(p => ({ ...p, property_address: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_fee_pct')}</label>
                <input type="number" step="1" min="0" max="100" value={form.referral_fee_pct} onChange={e => setForm(p => ({ ...p, referral_fee_pct: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm" />
                <p className="text-[9px] text-amber-500 font-bold mt-1">💡 {t('ref_25pct_note')}</p>
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{t('ref_notes')}</label>
                <textarea rows="2" value={form.notes} onChange={e => setForm(p => ({ ...p, notes: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-sm resize-none" />
              </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button onClick={() => setShowModal(false)}
                className="flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-widest text-slate-500 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 transition-colors">
                {t('ref_cancel')}
              </button>
              <button onClick={handleCreate} disabled={!form.client_name || saving}
                className="flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-widest bg-brand-600 text-white shadow-xl shadow-brand-500/20 hover:bg-brand-700 transition-all disabled:opacity-50">
                {saving ? t('ref_saving') : t('ref_save')}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

