"use client";
import { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useApp } from '@/lib/context';

const CHANNELS = [
  { key: 'whatsapp', icon: '💬', color: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 border-green-200 dark:border-green-800' },
  { key: 'email', icon: '📧', color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400 border-blue-200 dark:border-blue-800' },
  { key: 'phone', icon: '📱', color: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400 border-purple-200 dark:border-purple-800' },
  { key: 'in_person', icon: '🤝', color: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-amber-200 dark:border-amber-800' },
];

const CHANNEL_MAP = Object.fromEntries(CHANNELS.map(c => [c.key, c]));

const TEMPLATES = {
  propiedad_especifica: 'ofc_leads_template_property',
  comprar: 'ofc_leads_template_buy',
  vender: 'ofc_leads_template_sell',
  alquiler: 'ofc_leads_template_rent',
  otro: 'ofc_leads_template_general',
};

export default function CommunicationPanel({ lead, agentId, communications = [], onUpdate, onFollowUpCreated }) {
  const { t, lang } = useApp();
  const es = lang === 'es';

  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({ channel: 'whatsapp', direction: 'outbound', summary: '', follow_up_date: '' });

  const leadComms = communications.filter(c => c.inquiry_id === lead.id).sort((a, b) => new Date(b.created_at) - new Date(a.created_at));

  const handleSave = async () => {
    if (!form.summary.trim()) return;
    setSaving(true);
    try {
      const payload = {
        inquiry_id: lead.id,
        agent_id: agentId || null,
        channel: form.channel,
        direction: form.direction,
        summary: form.summary.trim(),
        follow_up_date: form.follow_up_date || null,
      };
      await supabase.from('lead_communications').insert(payload);

      // If follow-up date was set, also create a follow-up reminder
      if (form.follow_up_date) {
        await supabase.from('lead_follow_ups').insert({
          inquiry_id: lead.id,
          agent_id: agentId || null,
          due_date: form.follow_up_date,
          note: form.summary.trim(),
          status: 'pending',
        });
        onFollowUpCreated?.();
      }

      setForm({ channel: 'whatsapp', direction: 'outbound', summary: '', follow_up_date: '' });
      setShowForm(false);
      onUpdate?.();
    } catch (err) {
      console.error('Error saving communication:', err);
    } finally {
      setSaving(false);
    }
  };

  const timeAgo = (d) => {
    const mins = Math.floor((Date.now() - new Date(d)) / 60000);
    if (mins < 60) return `${mins}m`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d`;
    return new Date(d).toLocaleDateString();
  };

  // Build pre-filled WhatsApp message
  const getTemplateMessage = () => {
    const templateKey = TEMPLATES[lead.lead_type] || TEMPLATES.otro;
    let msg = t(templateKey);
    msg = msg.replace('{name}', lead.lead_name || '');
    const propTitle = lead.properties ? (es ? lead.properties.listing_title_es : lead.properties.listing_title_en) || lead.properties.name : '';
    msg = msg.replace('{property}', propTitle);
    return encodeURIComponent(msg);
  };

  const inputCls = "w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-sm text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500";

  return (
    <div className="space-y-4">
      {/* Quick Actions Row — WhatsApp + Email with templates */}
      <div className="flex flex-wrap items-center gap-2">
        {lead.lead_phone && (
          <a href={`https://wa.me/${lead.lead_phone.replace(/[^0-9]/g, '')}?text=${getTemplateMessage()}`} target="_blank" rel="noopener noreferrer"
            className="bg-[#25D366] hover:bg-[#128C7E] text-white px-3 py-1.5 rounded-lg text-[10px] font-bold flex items-center gap-1.5 transition-colors shadow-sm">
            💬 WhatsApp
          </a>
        )}
        {lead.lead_email && (
          <a href={`mailto:${lead.lead_email}?subject=${encodeURIComponent(es ? 'RE/MAX ALTITUD - Consulta' : 'RE/MAX ALTITUD - Inquiry')}`}
            className="bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600 text-slate-700 dark:text-white px-3 py-1.5 rounded-lg text-[10px] font-bold flex items-center gap-1.5 transition-colors shadow-sm">
            📧 Email
          </a>
        )}
        <button onClick={() => setShowForm(!showForm)}
          className="bg-nexus-blue hover:bg-blue-700 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold flex items-center gap-1.5 transition-colors shadow-sm ml-auto">
          <span>+</span> {t('ofc_leads_comm_log')}
        </button>
      </div>

      {/* Log Interaction Form */}
      {showForm && (
        <div className="bg-blue-50/50 dark:bg-blue-900/10 rounded-xl p-4 border border-blue-100 dark:border-blue-900/30 space-y-3">
          <div className="flex flex-wrap gap-2">
            {/* Channel */}
            <div className="flex gap-1">
              {CHANNELS.map(ch => (
                <button key={ch.key} onClick={() => setForm(p => ({ ...p, channel: ch.key }))}
                  className={`px-2.5 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${form.channel === ch.key ? ch.color + ' ring-2 ring-blue-400' : 'bg-white dark:bg-slate-800 text-slate-400 border-slate-200 dark:border-slate-700'}`}>
                  {ch.icon} {ch.key === 'in_person' ? (es ? 'Presencial' : 'In Person') : ch.key.charAt(0).toUpperCase() + ch.key.slice(1)}
                </button>
              ))}
            </div>
            {/* Direction */}
            <div className="flex gap-1 ml-auto">
              {['outbound', 'inbound'].map(dir => (
                <button key={dir} onClick={() => setForm(p => ({ ...p, direction: dir }))}
                  className={`px-2.5 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${form.direction === dir ? 'bg-slate-800 dark:bg-white text-white dark:text-slate-900 border-slate-800 dark:border-white' : 'bg-white dark:bg-slate-800 text-slate-400 border-slate-200 dark:border-slate-700'}`}>
                  {dir === 'outbound' ? '↗️' : '↙️'} {t('ofc_leads_comm_' + dir)}
                </button>
              ))}
            </div>
          </div>
          <textarea value={form.summary} onChange={e => setForm(p => ({ ...p, summary: e.target.value }))}
            placeholder={t('ofc_leads_comm_summary_placeholder')} rows={2} className={inputCls + " resize-none"} />
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 flex-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase whitespace-nowrap">🔔 {t('ofc_leads_comm_followup_date')}</label>
              <input type="date" value={form.follow_up_date} onChange={e => setForm(p => ({ ...p, follow_up_date: e.target.value }))}
                className="bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-1 text-xs text-slate-900 dark:text-white" />
            </div>
            <button onClick={handleSave} disabled={!form.summary.trim() || saving}
              className="bg-nexus-blue hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-[10px] font-bold transition-colors disabled:opacity-50 shadow-sm">
              {saving ? t('ofc_leads_comm_saving') : t('ofc_leads_comm_save')}
            </button>
          </div>
        </div>
      )}

      {/* Communication Timeline */}
      <div>
        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-2">{t('ofc_leads_comm_title')}</p>
        {leadComms.length === 0 ? (
          <div className="text-center py-4 text-slate-400">
            <p className="text-xs">{t('ofc_leads_comm_empty')}</p>
            <p className="text-[10px] mt-0.5">{t('ofc_leads_comm_empty_desc')}</p>
          </div>
        ) : (
          <div className="space-y-1.5 max-h-[240px] overflow-y-auto pr-1">
            {leadComms.map(comm => {
              const ch = CHANNEL_MAP[comm.channel] || CHANNEL_MAP.whatsapp;
              return (
                <div key={comm.id} className="flex items-start gap-2 py-1.5">
                  <div className="flex flex-col items-center gap-0.5 pt-0.5">
                    <span className="text-sm">{ch.icon}</span>
                    <span className="text-[8px] text-slate-400">{comm.direction === 'outbound' ? '↗️' : '↙️'}</span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-xs text-slate-700 dark:text-slate-300 leading-relaxed">{comm.summary}</p>
                    <div className="flex items-center gap-2 mt-0.5">
                      <span className="text-[9px] text-slate-400">{timeAgo(comm.created_at)}</span>
                      {comm.follow_up_date && (
                        <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full ${new Date(comm.follow_up_date) < new Date() ? 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400'}`}>
                          🔔 {new Date(comm.follow_up_date).toLocaleDateString()}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo } from 'react';
import { useAuth } from '@/lib/auth-context';

/* ═══════════════════════════════════════
   DASHBOARD TAB — Office Metrics & KPIs
   ═══════════════════════════════════════ */

const MONTH_NAMES_ES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const MONTH_NAMES_EN = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

function StatCard({ label, value, color = 'text-slate-900 dark:text-white', subtitle, icon }) {
  return (
    <div className="bg-white dark:bg-slate-800/80 rounded-2xl p-4 shadow-sm border border-slate-200/60 dark:border-slate-700/50 group hover:shadow-lg hover:scale-[1.02] transition-all duration-300 backdrop-blur-sm">
      <div className="flex items-start justify-between">
        <div>
          <p className="text-[9px] text-slate-400 dark:text-slate-500 uppercase font-black tracking-widest leading-none">{label}</p>
          <h3 className={`text-2xl font-black italic mt-1.5 ${color} tabular-nums`}>{value}</h3>
          {subtitle && <p className="text-[10px] text-slate-400 mt-0.5">{subtitle}</p>}
        </div>
        {icon && (
          <div className="w-8 h-8 rounded-xl bg-slate-50 dark:bg-slate-700/50 flex items-center justify-center text-slate-400 dark:text-slate-500 group-hover:bg-blue-50 dark:group-hover:bg-blue-900/20 group-hover:text-blue-500 transition-colors">
            {icon}
          </div>
        )}
      </div>
    </div>
  );
}

function MiniBarChart({ data, labels, lang, color = 'bg-nexus-blue' }) {
  const max = Math.max(...data, 1);
  return (
    <div className="flex items-end gap-1.5 h-32">
      {data.map((val, i) => (
        <div key={i} className="flex-1 flex flex-col items-center gap-1">
          <span className="text-[9px] font-bold text-slate-500 tabular-nums">${(val/1000).toFixed(1)}k</span>
          <div className="w-full bg-slate-100 dark:bg-slate-700/50 rounded-t-md overflow-hidden flex-1 flex items-end">
            <div
              className={`w-full ${color} rounded-t-md transition-all duration-700 ease-out opacity-85 hover:opacity-100`}
              style={{ height: `${Math.max((val / max) * 100, 4)}%` }}
            />
          </div>
          <span className="text-[8px] font-bold text-slate-400 uppercase">{labels[i]}</span>
        </div>
      ))}
    </div>
  );
}

function GaugeBar({ label, value, max, color = 'bg-emerald-500', prefix = '$' }) {
  const pct = max > 0 ? Math.min((value / max) * 100, 100) : 0;
  return (
    <div className="space-y-1.5">
      <div className="flex justify-between items-baseline">
        <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">{label}</span>
        <span className="text-sm font-black text-slate-900 dark:text-white tabular-nums">{prefix}{value.toLocaleString()}</span>
      </div>
      <div className="w-full h-3 bg-slate-100 dark:bg-slate-700/50 rounded-full overflow-hidden">
        <div className={`h-full rounded-full transition-all duration-1000 ease-out ${color}`} style={{ width: `${pct}%` }} />
      </div>
    </div>
  );
}

export default function DashboardTab({ 
  profiles = [], 
  teams = [], 
  inquiries = [], 
  expenses = [], 
  categories = [], 
  commissions = [], 
  reservations = [], 
  selectedOffice, 
  loading 
}) {
  const { isBroker, user } = useAuth(); // Assume we can use context, though impersonation might just be a router redirect or local storage
  const lang = 'es'; // default for office dashboard

  const now = new Date();
  const currentYear = now.getFullYear();
  const currentMonth = now.getMonth();
  const monthLabels = MONTH_NAMES_ES;

  // ── Agent Metrics ──
  const officeProfiles = profiles.filter(p => p.office === selectedOffice && p.role !== 'broker');
  const totalAgents = officeProfiles.length;

  // ── Billing (Facturacion) ──
  // Calculate this month and YTD
  const { monthBilling, ytdBilling, monthlyTrend } = useMemo(() => {
    let monthSum = 0;
    let ytdSum = 0;
    const trendData = [0,0,0,0,0,0];
    const trendLabels = [];

    for (let i = 5; i >= 0; i--) {
      const d = new Date(currentYear, currentMonth - i, 1);
      trendLabels.push(monthLabels[d.getMonth()]);
    }

    commissions.forEach(c => {
      const d = new Date(c.closing_date + 'T12:00:00');
      if (d.getFullYear() === currentYear) {
        ytdSum += Number(c.gross_commission) || 0;
      }
      if (d.getFullYear() === currentYear && d.getMonth() === currentMonth) {
        monthSum += Number(c.gross_commission) || 0;
      }
      // trend
      for (let i = 5; i >= 0; i--) {
        const trendMonth = new Date(currentYear, currentMonth - i, 1);
        if (d.getFullYear() === trendMonth.getFullYear() && d.getMonth() === trendMonth.getMonth()) {
          trendData[5-i] += Number(c.gross_commission) || 0;
        }
      }
    });
    return { monthBilling: monthSum, ytdBilling: ytdSum, monthlyTrend: { data: trendData, labels: trendLabels } };
  }, [commissions, currentYear, currentMonth, monthLabels]);

  // ── Channels (Buyers vs Sellers) ──
  const { buyerSources, sellerSources } = useMemo(() => {
    const bSources = {};
    const sSources = {};
    inquiries.filter(i => i.status === 'converted').forEach(i => {
      const source = i.source || 'manual';
      if (i.lead_type === 'comprar' || i.lead_type === 'alquiler') {
        bSources[source] = (bSources[source] || 0) + 1;
      } else if (i.lead_type === 'vender' || i.lead_type === 'propiedad_especifica') {
        sSources[source] = (sSources[source] || 0) + 1;
      }
    });
    return { 
      buyerSources: Object.entries(bSources).map(([k,v]) => ({ name: k, count: v })).sort((a,b)=>b.count-a.count),
      sellerSources: Object.entries(sSources).map(([k,v]) => ({ name: k, count: v })).sort((a,b)=>b.count-a.count)
    };
  }, [inquiries]);

  // ── Expenses (Gastos) ──
  const expensesByCategory = useMemo(() => {
    const catMap = Object.fromEntries(categories.map(c => [c.id, c.name]));
    const totals = {};
    let totalEx = 0;
    expenses.forEach(ex => {
      const d = new Date(ex.expense_date + 'T12:00:00');
      // Let's do YTD expenses
      if (d.getFullYear() === currentYear) {
        const amt = Number(ex.amount) || 0;
        const cname = catMap[ex.category_id] || 'Otros';
        totals[cname] = (totals[cname] || 0) + amt;
        totalEx += amt;
      }
    });
    return {
      total: totalEx,
      items: Object.entries(totals).map(([k,v]) => ({ name: k, amount: v })).sort((a,b)=>b.amount-a.amount)
    };
  }, [expenses, categories, currentYear]);

  // ── Reservometro ──
  const { loiTotal, spaTotal, upcomingClosings } = useMemo(() => {
    let loi = 0;
    let spa = 0;
    const upcoming = [];
    reservations.filter(r => r.status === 'pending' || r.status === 'signed').forEach(r => {
      if (r.type === 'LOI') loi += Number(r.reservation_amount) || 0;
      if (r.type === 'SPA') spa += Number(r.reservation_amount) || 0;

      const ed = r.expected_sign_date ? new Date(r.expected_sign_date + 'T12:00:00') : null;
      if (ed && ed >= now) {
        upcoming.push(r);
      }
    });
    upcoming.sort((a,b) => new Date(a.expected_sign_date) - new Date(b.expected_sign_date));
    return { loiTotal: loi, spaTotal: spa, upcomingClosings: upcoming.slice(0, 5) };
  }, [reservations, now]);

  // ── Top Agents (Month and Year) ──
  const { topMonth, topYear } = useMemo(() => {
    const agentMapMonth = {};
    const agentMapYear = {};

    commissions.forEach(c => {
      const d = new Date(c.closing_date + 'T12:00:00');
      const aid = c.agent_id;
      const isListing = c.side === 'listing' || c.side === 'both';
      const isSelling = c.side === 'selling' || c.side === 'both';
      const amt = Number(c.agent_amount) || 0;

      if (!agentMapYear[aid]) agentMapYear[aid] = { id: aid, name: c.profiles?.full_name, avatar: c.profiles?.avatar_url, listAmt: 0, sellAmt: 0 };
      if (!agentMapMonth[aid]) agentMapMonth[aid] = { id: aid, name: c.profiles?.full_name, avatar: c.profiles?.avatar_url, listAmt: 0, sellAmt: 0 };

      if (d.getFullYear() === currentYear) {
        if (isListing) agentMapYear[aid].listAmt += amt;
        if (isSelling) agentMapYear[aid].sellAmt += amt;

        if (d.getMonth() === currentMonth) {
          if (isListing) agentMapMonth[aid].listAmt += amt;
          if (isSelling) agentMapMonth[aid].sellAmt += amt;
        }
      }
    });

    const sortAgents = (map, key) => Object.values(map).sort((a,b) => b[key] - a[key]).slice(0,3);

    return {
      topMonth: {
        listers: sortAgents(agentMapMonth, 'listAmt'),
        closers: sortAgents(agentMapMonth, 'sellAmt')
      },
      topYear: {
        listers: sortAgents(agentMapYear, 'listAmt'),
        closers: sortAgents(agentMapYear, 'sellAmt')
      }
    };
  }, [commissions, currentYear, currentMonth]);

