      const { error } = await supabase.from('account_transactions').insert({
        profile_id: selectedAgentId,
        type: transactionType,
        amount: parseFloat(txForm.amount),
        category: txForm.category,
        description: txForm.description,
        date: txForm.date,
        added_by: profile?.id
      });
