"use client";

import { useState, useMemo } from 'react';
import { useApp } from '@/lib/context';
import { useAuth } from '@/lib/auth-context';

/* ═══════════════════════════════════════════════════════════════
   OFFICE FINANCE TAB — Expenses, Incomes & Petty Cash Tracking
   ═══════════════════════════════════════════════════════════════ */

export default function OfficeFinanceTab({ expenses = [], categories = [], funds = [], transactions = [], salaries = [], profiles = [] }) {
  const { t } = useApp();
  const { supabase, isBroker, isOfficeAssistant, profile } = useAuth();
  const [loading, setLoading] = useState(false);
  const [filterCategory, setFilterCategory] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [timeframe, setTimeframe] = useState('this_month');
  const [activeTab, setActiveTab] = useState('expense'); // 'expense' or 'income'

  // Local state for optimistic updates
  const [localExpenses, setLocalExpenses] = useState(expenses);
  const [localFunds, setLocalFunds] = useState(funds);
  const [localTxs, setLocalTxs] = useState(transactions);

  // Modals
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(null); // holds expense/income object

  const fmt = (num, curr = 'CRC') => new Intl.NumberFormat('en-US', { style: 'currency', currency: curr, minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(num || 0);

  // ── Aggregates ──
  const now = new Date();

  const dateRange = useMemo(() => {
    const d = new Date();
    const y = d.getFullYear();
    const m = d.getMonth();

    switch (timeframe) {
      case 'last_month': {
        const start = new Date(y, m - 1, 1).toISOString().slice(0,10);
        const end = new Date(y, m, 0).toISOString().slice(0,10);
        return { start, end };
      }
      case 'next_month': {
        const start = new Date(y, m + 1, 1).toISOString().slice(0,10);
        const end = new Date(y, m + 2, 0).toISOString().slice(0,10);
        return { start, end };
      }
      case 'ytd': {
        const start = `${y}-01-01`;
        const end = new Date(y, 11, 31).toISOString().slice(0,10);
        return { start, end };
      }
      case 'all': {
        return { start: '1900-01-01', end: '2100-12-31' };
      }
      case 'this_month':
      default: {
        const start = new Date(y, m, 1).toISOString().slice(0,10);
        const end = new Date(y, m + 1, 0).toISOString().slice(0,10);
        return { start, end };
      }
    }
  }, [timeframe]);

  const getTimeframeLabel = (tf) => {
    const monthNames = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];
    const m = new Date().getMonth();
    if (tf === 'this_month') return monthNames[m];
    if (tf === 'last_month') return monthNames[(m - 1 + 12) % 12];
    if (tf === 'next_month') return monthNames[(m + 1) % 12];
    if (tf === 'ytd') return 'YTD - Año a la Fecha';
    if (tf === 'all') return 'Total';
    return tf;
  };

  // Split expenses vs incomes
  const expensesList = localExpenses.filter(e => e.transaction_type === 'expense' || !e.transaction_type);
  const incomesList = localExpenses.filter(e => e.transaction_type === 'income');

  // Completed in period (Paid expenses / Received incomes)
  const completedExpenses = expensesList.filter(e => e.status === 'paid' && e.paid_date >= dateRange.start && e.paid_date <= dateRange.end);
  const completedExpensesCRC = completedExpenses.filter(e => e.currency === 'CRC').reduce((acc, e) => acc + Number(e.amount), 0);
  const completedExpensesUSD = completedExpenses.filter(e => e.currency === 'USD').reduce((acc, e) => acc + Number(e.amount), 0);

  const completedIncomes = incomesList.filter(e => e.status === 'received' && e.paid_date >= dateRange.start && e.paid_date <= dateRange.end);
  const completedIncomesCRC = completedIncomes.filter(e => e.currency === 'CRC').reduce((acc, e) => acc + Number(e.amount), 0);
  const completedIncomesUSD = completedIncomes.filter(e => e.currency === 'USD').reduce((acc, e) => acc + Number(e.amount), 0);

  // Pending in period
  const pendingExpenses = expensesList.filter(e => e.status === 'pending' && e.due_date >= dateRange.start && e.due_date <= dateRange.end);
  const pendingExpensesCRC = pendingExpenses.filter(e => e.currency === 'CRC').reduce((acc, e) => acc + Number(e.amount), 0);
  const pendingExpensesUSD = pendingExpenses.filter(e => e.currency === 'USD').reduce((acc, e) => acc + Number(e.amount), 0);

  const pendingIncomes = incomesList.filter(e => e.status === 'pending' && e.due_date >= dateRange.start && e.due_date <= dateRange.end);
  const pendingIncomesCRC = pendingIncomes.filter(e => e.currency === 'CRC').reduce((acc, e) => acc + Number(e.amount), 0);
  const pendingIncomesUSD = pendingIncomes.filter(e => e.currency === 'USD').reduce((acc, e) => acc + Number(e.amount), 0);

  // Petty Cash combined balance
  const pettyCashBalanceCRC = localFunds.filter(f => f.currency === 'CRC').reduce((acc, f) => {
    const txs = localTxs.filter(t => t.fund_id === f.id);
    const balance = Number(f.initial_amount) + txs.reduce((sum, t) => (t.type === 'replenish' || t.type === 'income') ? sum + Number(t.amount) : sum - Number(t.amount), 0);
    return acc + balance;
  }, 0);

  // Filtered List based on active tab
  const activeList = activeTab === 'expense' ? expensesList : incomesList;
  const filteredList = activeList.filter(e => {
    if (filterCategory && e.category_id !== filterCategory) return false;
    if (filterStatus && e.status !== filterStatus) return false;
    return true;
  }).sort((a, b) => new Date(b.due_date) - new Date(a.due_date));

  // Category breakdown for active tab
  const categoryStats = useMemo(() => {
    return categories
      .filter(c => c.type === activeTab || c.type === 'both' || !c.type)
      .map(cat => {
        const catItems = activeList.filter(e => e.category_id === cat.id && (e.status === 'paid' || e.status === 'received') && e.paid_date >= dateRange.start && e.paid_date <= dateRange.end);
        const totalCRC = catItems.filter(e => e.currency === 'CRC').reduce((sum, e) => sum + Number(e.amount), 0);
        const totalUSD = catItems.filter(e => e.currency === 'USD').reduce((sum, e) => sum + Number(e.amount), 0);
        return { ...cat, totalCRC, totalUSD };
      }).sort((a, b) => a.sort_order - b.sort_order);
  }, [categories, activeList, dateRange, activeTab]);

  // Handle Confirm Transaction
  const handleConfirmTransaction = async (item, source, fundId = null) => {
    setLoading(true);
    const today = new Date().toISOString().split('T')[0];
    const isIncome = item.transaction_type === 'income';
    const newStatus = isIncome ? 'received' : 'paid';

    // Update status
    const { error } = await supabase.from('office_expenses').update({
      status: newStatus,
      paid_date: today,
      paid_by: profile.id,
      payment_source: source,
      petty_cash_fund_id: fundId
    }).eq('id', item.id);

    if (!error) {
      setLocalExpenses(prev => prev.map(e => e.id === item.id ? { ...e, status: newStatus, paid_date: today, payment_source: source } : e));

      // If petty cash, create transaction
      if (source === 'petty_cash' && fundId) {
        const tx = {
          fund_id: fundId,
          type: isIncome ? 'income' : 'expense',
          amount: item.amount,
          expense_id: item.id, // we use expense_id for both to keep the schema simple
          description: item.description,
          created_by: profile.id
        };
        const { data: newTx } = await supabase.from('petty_cash_transactions').insert(tx).select().single();
        if (newTx) setLocalTxs(prev => [newTx, ...prev]);
      }
    }

    setLoading(false);
    setShowConfirmModal(null);
  };

  if (!isBroker && !isOfficeAssistant) {
    return <div className="p-10 text-center text-slate-500">Acceso denegado.</div>;
  }

  return (
    <div className="space-y-8 pb-12">
      {/* ── Timeframe Filter ── */}
      <div className="flex justify-between items-center bg-slate-50 dark:bg-slate-800/50 p-2 rounded-xl border border-slate-200 dark:border-slate-700">
        <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 pl-2">Periodo</span>
        <select value={timeframe} onChange={e => setTimeframe(e.target.value)} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg px-3 py-1.5 text-xs font-bold text-slate-700 dark:text-slate-200 shadow-sm focus:ring-2 focus:ring-nexus-blue outline-none transition-all">
          <option value="this_month">{getTimeframeLabel('this_month')}</option>
          <option value="last_month">{getTimeframeLabel('last_month')}</option>
          <option value="next_month">{getTimeframeLabel('next_month')}</option>
          <option value="ytd">{getTimeframeLabel('ytd')}</option>
          <option value="all">{getTimeframeLabel('all')}</option>
        </select>
      </div>

      {/* ── Summary Cards ── */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-slate-800 rounded-[24px] p-5 shadow-sm border border-slate-200 dark:border-slate-700">
          <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">Ingresos ({getTimeframeLabel(timeframe)})</p>
          <div className="mt-2 space-y-1">
            <p className="text-xl font-black italic text-emerald-500">{fmt(completedIncomesCRC, 'CRC')}</p>
            {completedIncomesUSD > 0 && <p className="text-sm font-bold text-emerald-400/70">{fmt(completedIncomesUSD, 'USD')}</p>}
          </div>
        </div>
        <div className="bg-white dark:bg-slate-800 rounded-[24px] p-5 shadow-sm border border-slate-200 dark:border-slate-700">
          <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">Gastos ({getTimeframeLabel(timeframe)})</p>
          <div className="mt-2 space-y-1">
            <p className="text-xl font-black italic text-red-500">{fmt(completedExpensesCRC, 'CRC')}</p>
            {completedExpensesUSD > 0 && <p className="text-sm font-bold text-red-400/70">{fmt(completedExpensesUSD, 'USD')}</p>}
          </div>
        </div>
        <div className="bg-white dark:bg-slate-800 rounded-[24px] p-5 shadow-sm border border-slate-200 dark:border-slate-700">
          <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{t('ofc_fin_petty_cash_balance')}</p>
          <div className="mt-2 space-y-1">
            <p className="text-xl font-black italic text-blue-500">{fmt(pettyCashBalanceCRC, 'CRC')}</p>
          </div>
        </div>
        <div className="bg-white dark:bg-slate-800 rounded-[24px] p-5 shadow-sm border border-slate-200 dark:border-slate-700 flex flex-col justify-center gap-2">
          <button onClick={() => setShowExpenseModal('income')} className="w-full bg-emerald-500 hover:bg-emerald-600 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-emerald-500/20 transition-all">
            + Nuevo Ingreso
          </button>
          <button onClick={() => setShowExpenseModal('expense')} className="w-full bg-nexus-blue hover:bg-blue-700 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-500/20 transition-all">
            + Nuevo Gasto
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* ── Left Column: Expense List & Categories ── */}
        <div className="lg:col-span-2 space-y-8">

          {/* Tabs */}
          <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl w-full max-w-sm">
            <button
              onClick={() => { setActiveTab('expense'); setFilterCategory(''); setFilterStatus(''); }}
              className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'expense' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Gastos
            </button>
            <button
              onClick={() => { setActiveTab('income'); setFilterCategory(''); setFilterStatus(''); }}
              className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'income' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Ingresos
            </button>
          </div>

          {/* Category Breakdown */}
          <div className="bg-white dark:bg-slate-800 rounded-[32px] shadow-sm border border-slate-200 dark:border-slate-700 p-6">
            <h3 className="text-sm font-black text-slate-900 dark:text-white mb-6 uppercase tracking-widest">
              Categorías de {activeTab === 'expense' ? 'Gastos' : 'Ingresos'} ({getTimeframeLabel(timeframe)})
            </h3>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {categoryStats.map(cat => (
                <div key={cat.id} className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-4 border border-slate-100 dark:border-slate-700">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-xl">{cat.icon}</span>
                    <span className="text-[10px] font-black uppercase tracking-widest text-slate-600 dark:text-slate-400">{cat.label_es}</span>
                  </div>
                  <p className="text-sm font-bold text-slate-900 dark:text-white">{fmt(cat.totalCRC, 'CRC')}</p>
                  {cat.totalUSD > 0 && <p className="text-[10px] text-slate-400">{fmt(cat.totalUSD, 'USD')}</p>}
                </div>
              ))}
              {categoryStats.length === 0 && <p className="text-xs text-slate-400 col-span-full">No hay categorías configuradas.</p>}
            </div>
          </div>

          {/* Transaction List */}
          <div className="bg-white dark:bg-slate-800 rounded-[32px] shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
            <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
              <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest">
                Lista de {activeTab === 'expense' ? 'Gastos' : 'Ingresos'}
              </h3>
              <div className="flex gap-2 w-full sm:w-auto">
                <select value={filterCategory} onChange={e => setFilterCategory(e.target.value)} className="bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-[10px] font-bold uppercase tracking-widest">
                  <option value="">{t('ofc_fin_filter_all_cats')}</option>
                  {categories.filter(c => c.type === activeTab || c.type === 'both' || !c.type).map(c => <option key={c.id} value={c.id}>{c.label_es}</option>)}
                </select>
                <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)} className="bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-2 text-[10px] font-bold uppercase tracking-widest">
                  <option value="">{t('ofc_fin_filter_all_status')}</option>
                  <option value="pending">{t('ofc_fin_status_pending')}</option>
                  <option value={activeTab === 'expense' ? 'paid' : 'received'}>{activeTab === 'expense' ? t('ofc_fin_status_paid') : 'RECIBIDO'}</option>
                </select>
              </div>
            </div>

            <div className="divide-y divide-slate-100 dark:divide-slate-700/50 max-h-[600px] overflow-y-auto">
              {filteredList.length === 0 ? (
                <div className="p-8 text-center text-slate-400 text-xs font-bold uppercase tracking-widest">No hay registros que mostrar</div>
              ) : filteredList.map(item => {
                const cat = categories.find(c => c.id === item.category_id);
                return (
                  <div key={item.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50/50 dark:hover:bg-white/5 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center text-lg shadow-sm">
                        {cat?.icon || (activeTab === 'expense' ? '💸' : '💰')}
                      </div>
                      <div>
                        <div className="flex items-center gap-2">
                          <p className="text-sm font-bold text-slate-900 dark:text-white">{item.description}</p>
                          {item.is_recurring && <span className="text-[10px] text-blue-500" title={t('ofc_fin_recurring')}>🔄</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-medium">
                          {item.due_date && new Date(item.due_date + 'T12:00:00').toLocaleDateString()} · {cat?.label_es}
                        </p>
                      </div>
                    </div>
                    <div className="text-right flex flex-col items-end gap-1">
                      <p className={`text-sm font-black tabular-nums ${activeTab === 'expense' ? 'text-slate-900 dark:text-white' : 'text-emerald-500'}`}>
                        {activeTab === 'income' ? '+' : ''}{fmt(item.amount, item.currency)}
                      </p>
                      {item.status === 'pending' ? (
                        <button onClick={() => setShowConfirmModal(item)} className="bg-amber-100 text-amber-700 hover:bg-amber-200 dark:bg-amber-900/40 dark:text-amber-400 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest transition-colors">
                          {activeTab === 'expense' ? 'MARCAR PAGADO' : 'MARCAR RECIBIDO'}
                        </button>
                      ) : (
                        <span className="bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-400 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">
                          {activeTab === 'expense' ? t('ofc_fin_status_paid') : 'RECIBIDO'} {item.payment_source === 'petty_cash' ? '💵' : '🏦'}
                        </span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* ── Right Column: Petty Cash & Config ── */}
        <div className="space-y-8">

          {/* Petty Cash Funds */}
          <div className="bg-white dark:bg-slate-800 rounded-[32px] shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
            <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700">
              <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2">
                <span>💵</span> {t('ofc_fin_petty_cash')}
              </h3>
            </div>
            <div className="divide-y divide-slate-100 dark:divide-slate-700/50">
              {localFunds.map(fund => {
                const assistant = profiles.find(p => p.id === fund.assistant_id);
                const fundTxs = localTxs.filter(t => t.fund_id === fund.id);
                const balance = Number(fund.initial_amount) + fundTxs.reduce((sum, t) => (t.type === 'replenish' || t.type === 'income') ? sum + Number(t.amount) : sum - Number(t.amount), 0);

                return (
                  <div key={fund.id} className="p-6">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-3">
                        <img src={assistant?.avatar_url || `https://ui-avatars.com/api/?name=${encodeURIComponent(assistant?.full_name || 'Asistente')}`} className="w-8 h-8 rounded-full border-2 border-slate-200" alt=""/>
                        <div>
                          <p className="text-xs font-bold text-slate-900 dark:text-white">{assistant?.full_name || 'Asistente'}</p>
                          <p className="text-[9px] text-slate-400 uppercase tracking-widest">Responsable</p>
                        </div>
                      </div>
                      <p className="text-lg font-black text-blue-500">{fmt(balance, fund.currency)}</p>
                    </div>
                    {fundTxs.slice(0, 3).length > 0 && (
                      <div className="bg-slate-50 dark:bg-slate-900/50 rounded-xl p-3 space-y-2">
                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">{t('ofc_fin_petty_txs')}</p>
                        {fundTxs.slice(0, 3).map(tx => {
                          const isPositive = tx.type === 'replenish' || tx.type === 'income';
                          return (
                            <div key={tx.id} className="flex justify-between items-center text-[10px]">
                              <span className="text-slate-600 dark:text-slate-400 truncate pr-2">
                                {isPositive ? `🟢 ${tx.type === 'replenish' ? 'Recarga' : 'Ingreso'}` : `🔴 ${tx.description}`}
                              </span>
                              <span className={`font-bold ${isPositive ? 'text-emerald-500' : 'text-slate-900 dark:text-white'}`}>
                                {isPositive ? '+' : '-'}{fmt(tx.amount, fund.currency)}
                              </span>
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })}
              {localFunds.length === 0 && <div className="p-6 text-center text-xs text-slate-400">No hay fondos de caja chica configurados.</div>}
            </div>
          </div>

        </div>
      </div>

      {/* ── Modals ── */}

      {/* Confirm Transaction Modal */}
      {showConfirmModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm" onClick={() => setShowConfirmModal(null)}>
          <div className="bg-white dark:bg-slate-800 rounded-[32px] p-8 max-w-md w-full shadow-2xl space-y-6" onClick={e => e.stopPropagation()}>
            <h3 className="text-xl font-black italic text-slate-900 dark:text-white">
              {showConfirmModal.transaction_type === 'income' ? 'MARCAR RECIBIDO' : 'MARCAR PAGADO'}
            </h3>
            <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-2xl">
              <p className="text-sm font-bold text-slate-900 dark:text-white">{showConfirmModal.description}</p>
              <p className="text-2xl font-black text-emerald-500 mt-1">{fmt(showConfirmModal.amount, showConfirmModal.currency)}</p>
            </div>
            <div className="space-y-3">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                {showConfirmModal.transaction_type === 'income' ? '¿A dónde ingresó el dinero?' : '¿De dónde salió el dinero?'}
              </p>
              <button disabled={loading} onClick={() => handleConfirmTransaction(showConfirmModal, 'bank')} className="w-full p-4 rounded-2xl border-2 border-slate-200 dark:border-slate-700 hover:border-emerald-500 flex items-center justify-between group transition-all">
                <div className="flex items-center gap-3">
                  <span className="text-2xl">🏦</span>
                  <div className="text-left">
                    <p className="text-sm font-bold text-slate-900 dark:text-white">Cuenta Bancaria</p>
                    <p className="text-[10px] text-slate-500">Transferencia o tarjeta corporativa</p>
                  </div>
                </div>
              </button>

              {/* Petty cash options if currencies match */}
              {localFunds.filter(f => f.currency === showConfirmModal.currency).map(f => {
                const assistant = profiles.find(p => p.id === f.assistant_id);
                const fundTxs = localTxs.filter(t => t.fund_id === f.id);
                const balance = Number(f.initial_amount) + fundTxs.reduce((sum, t) => (t.type === 'replenish' || t.type === 'income') ? sum + Number(t.amount) : sum - Number(t.amount), 0);

                const isIncome = showConfirmModal.transaction_type === 'income';
                const hasSufficientFunds = balance >= showConfirmModal.amount;
                // Only disable if it's an expense and there's no money. If it's income, it always adds money.
                const isDisabled = loading || (!isIncome && !hasSufficientFunds);

                return (
                  <button key={f.id} disabled={isDisabled} onClick={() => handleConfirmTransaction(showConfirmModal, 'petty_cash', f.id)} className="w-full p-4 rounded-2xl border-2 border-slate-200 dark:border-slate-700 hover:border-blue-500 flex items-center justify-between group transition-all disabled:opacity-50 disabled:cursor-not-allowed">
                    <div className="flex items-center gap-3">
                      <span className="text-2xl">💵</span>
                      <div className="text-left">
                        <p className="text-sm font-bold text-slate-900 dark:text-white">{t('ofc_fin_pay_from_petty')} ({assistant?.full_name?.split(' ')[0]})</p>
                        <p className={`text-[10px] font-black ${(!isIncome && !hasSufficientFunds) ? 'text-red-500' : 'text-slate-500'}`}>Balance actual: {fmt(balance, f.currency)}</p>
                      </div>
                    </div>
                  </button>
                )
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { useApp } from '@/lib/context';
import { useAuth } from '@/lib/auth-context';
import PropertyStatusBadge from '@/components/propiedades/PropertyStatusBadge';
import { formatPrice } from '@/components/propiedades/PropertyCard';
import Link from 'next/link';

export default function PropertyApprovalTab() {
  const { lang } = useApp();
  const { profile } = useAuth();
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('pending_approval');
  const [expanded, setExpanded] = useState(null);
  const [rejectNotes, setRejectNotes] = useState('');
  const [actionLoading, setActionLoading] = useState(false);
  const [descLang, setDescLang] = useState('es'); // bilingual description toggle
  const [selectedIds, setSelectedIds] = useState(new Set()); // batch selection

  const fetchProperties = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('properties')
      .select('*, property_images(image_url, priority)')
      .order('submitted_at', { ascending: false });
    if (!error) setProperties(data || []);
    setLoading(false);
  };

  useEffect(() => { fetchProperties(); }, []);

  const filtered = filter === 'all'
    ? properties
    : properties.filter(p => p.status === filter);

  const handleApprove = async (id) => {
    setActionLoading(true);
    const { error } = await supabase.from('properties').update({
      status: 'approved', reviewed_at: new Date().toISOString(), reviewed_by: profile?.id || null, broker_notes: null
    }).eq('id', id);
    if (!error) await fetchProperties();
    setActionLoading(false);
    setExpanded(null);
  };

  const handleApproveAndPublish = async (id) => {
    setActionLoading(true);
    try {
      // First approve
      const { error: approveError } = await supabase.from('properties').update({
        status: 'approved', reviewed_at: new Date().toISOString(), reviewed_by: profile?.id || null, broker_notes: null
      }).eq('id', id);
      if (approveError) throw approveError;

      // Then publish via API
      const res = await fetch('/api/properties/publish', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ propertyId: id }),
      });
      const data = await res.json();
      if (!data.success) {
        console.warn('Publish note:', data.message || data.error);
      }

      await fetchProperties();
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setActionLoading(false);
    setExpanded(null);
  };

  const handleReject = async (id) => {
    if (!rejectNotes.trim()) return alert(lang === 'en' ? 'Please add notes' : 'Agrega notas para el agente');
    setActionLoading(true);
    const { error } = await supabase.from('properties').update({
      status: 'needs_changes', reviewed_at: new Date().toISOString(), reviewed_by: profile?.id || null, broker_notes: rejectNotes
    }).eq('id', id);
    if (!error) { await fetchProperties(); setRejectNotes(''); }
    setActionLoading(false);
    setExpanded(null);
  };

  const filters = [
    { key: 'pending_approval', label: lang === 'en' ? 'Pending' : 'Pendientes', count: properties.filter(p => p.status === 'pending_approval').length },
    { key: 'needs_changes', label: lang === 'en' ? 'Changes Req.' : 'Necesita Cambios', count: properties.filter(p => p.status === 'needs_changes').length },
    { key: 'approved', label: lang === 'en' ? 'Approved' : 'Aprobadas', count: properties.filter(p => p.status === 'approved').length },
    { key: 'published', label: lang === 'en' ? 'Published' : 'Publicadas', count: properties.filter(p => p.status === 'published').length },
    { key: 'all', label: lang === 'en' ? 'All' : 'Todas', count: properties.length },
  ];

  // Batch approve
  const handleBatchApprove = async () => {
    if (selectedIds.size === 0) return;
    setActionLoading(true);
    const ids = [...selectedIds];
    for (const id of ids) {
      await supabase.from('properties').update({
        status: 'approved', reviewed_at: new Date().toISOString(), reviewed_by: profile?.id || null, broker_notes: null
      }).eq('id', id);
    }
    setSelectedIds(new Set());
    await fetchProperties();
    setActionLoading(false);
  };

  const toggleSelect = (id) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  return (
    <div>
      {/* Filter tabs + batch actions */}
      <div className="flex items-center justify-between gap-2 mb-4 flex-wrap">
        <div className="flex items-center gap-2 flex-wrap">
          {filters.map(f => (
            <button key={f.key} onClick={() => setFilter(f.key)}
              className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${filter === f.key ? 'bg-nexus-blue text-white' : 'bg-slate-800 text-slate-400 hover:text-white hover:bg-slate-700'}`}>
              {f.label} <span className="ml-1 opacity-70">({f.count})</span>
            </button>
          ))}
        </div>
        {selectedIds.size > 0 && (
          <button onClick={handleBatchApprove} disabled={actionLoading}
            className="px-4 py-1.5 rounded-lg text-xs font-semibold bg-green-600 hover:bg-green-700 text-white transition-all disabled:opacity-50 flex items-center gap-1.5">
            ✅ {lang === 'en' ? `Approve ${selectedIds.size} Selected` : `Aprobar ${selectedIds.size} Seleccionadas`}
          </button>
        )}
      </div>

      {loading ? (
        <div className="text-center py-8">
          <div className="w-6 h-6 border-2 border-nexus-blue border-t-transparent rounded-full animate-spin mx-auto" />
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
          <p className="text-sm">{lang === 'en' ? 'No properties in this category' : 'Sin propiedades en esta categoría'}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map(p => {
            const isOpen = expanded === p.id;
            const mainImg = p.property_images?.sort((a, b) => a.priority - b.priority)?.[0]?.image_url;
            const title = (lang === 'en' ? p.listing_title_en : p.listing_title_es) || p.name;
            const photoCount = p.property_images?.length || 0;

            return (
              <div key={p.id} className="bg-slate-800/50 rounded-xl border border-slate-700 overflow-hidden">
                {/* Summary row */}
                <div className="flex items-center gap-4 p-4 hover:bg-slate-800 transition-colors">
                  {/* Batch select checkbox */}
                  {p.status === 'pending_approval' && (
                    <input type="checkbox" checked={selectedIds.has(p.id)} onChange={() => toggleSelect(p.id)}
                      className="w-4 h-4 rounded border-slate-600 text-nexus-blue focus:ring-nexus-blue bg-slate-800 cursor-pointer flex-shrink-0" />
                  )}
                  <button onClick={() => setExpanded(isOpen ? null : p.id)} className="flex items-center gap-4 flex-1 min-w-0 text-left">
                    {/* Thumbnail */}
                    <div className="w-14 h-14 rounded-lg bg-slate-700 overflow-hidden flex-shrink-0">
                      {mainImg ? <img src={mainImg} className="w-full h-full object-cover" alt="" /> : (
                        <div className="w-full h-full flex items-center justify-center text-slate-500"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg></div>
                      )}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-bold text-white truncate">{title}</p>
                      <p className="text-xs text-slate-400">{formatPrice(p.list_price, p.list_price_currency_id)} · {p.unparsed_address || '—'}</p>
                    </div>
                  </button>
                  <PropertyStatusBadge status={p.status} lang={lang} />
                  {/* View detail link */}
                  <Link
                    href={`/propiedades/${p.id}`}
                    className="text-slate-400 hover:text-nexus-blue transition-colors p-1.5"
                    title={lang === 'en' ? 'View details' : 'Ver detalle'}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                  </Link>
                  <button onClick={() => setExpanded(isOpen ? null : p.id)} className="text-slate-500">
                    <svg className={`w-4 h-4 transition-transform ${isOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </button>
                </div>

                {/* Expanded detail */}
                {isOpen && (
                  <div className="border-t border-slate-700 p-4">
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-sm mb-4">
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Owner' : 'Propietario'}</span><p className="text-white font-medium">{p.owner_name || '—'}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Phone' : 'Teléfono'}</span><p className="text-white font-medium">{p.owner_phones || '—'}</p></div>
                      <div><span className="text-slate-500 text-xs">Email</span><p className="text-white font-medium">{p.owner_email || '—'}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Agreement' : 'Contrato'}</span><p className={`font-medium ${p.listing_agreement ? 'text-green-400' : 'text-red-400'}`}>{p.listing_agreement ? '✅ Firmado' : '❌ Pendiente'}</p></div>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-sm mb-4">
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Bedrooms' : 'Habitaciones'}</span><p className="text-white">{p.bedrooms_total || 0}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Bathrooms' : 'Baños'}</span><p className="text-white">{p.bathrooms_full || 0}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Lot' : 'Terreno'}</span><p className="text-white">{p.lot_size_area ? `${Number(p.lot_size_area).toLocaleString()} m²` : '—'}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Construction' : 'Construcción'}</span><p className="text-white">{p.construction_size ? `${Number(p.construction_size).toLocaleString()} m²` : '—'}</p></div>
                    </div>

                    {/* Commission & Classification */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-sm mb-4">
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Listing Comm.' : 'Comisión Listing'}</span><p className="text-white font-medium">{p.listing_side_comm != null ? `${p.listing_side_comm}%` : '—'}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Selling Comm.' : 'Comisión Selling'}</span><p className="text-white font-medium">{p.selling_side_comm != null ? `${p.selling_side_comm}%` : '—'}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Property Type' : 'Tipo'}</span><p className={`font-medium ${p.property_type_id ? 'text-white' : 'text-amber-400'}`}>{p.property_type_id ? `ID ${p.property_type_id}` : '⚠ ' + (lang === 'en' ? 'Not set' : 'Sin definir')}</p></div>
                      <div><span className="text-slate-500 text-xs">{lang === 'en' ? 'Location ID' : 'Ubicación ID'}</span><p className={`font-medium ${p.location_id ? 'text-white' : 'text-amber-400'}`}>{p.location_id || ('⚠ ' + (lang === 'en' ? 'Not set' : 'Sin definir'))}</p></div>
                    </div>

                    {/* Photo thumbnails */}
                    {photoCount > 0 && (
                      <div className="mb-4">
                        <p className="text-xs text-slate-500 mb-2">📸 {photoCount} {lang === 'en' ? 'photos' : 'fotos'}</p>
                        <div className="flex gap-1.5 overflow-x-auto pb-1">
                          {p.property_images?.sort((a, b) => a.priority - b.priority).slice(0, 6).map((img, i) => (
                            <img key={i} src={img.image_url} className="w-16 h-16 rounded-lg object-cover flex-shrink-0" alt="" />
                          ))}
                          {photoCount > 6 && (
                            <div className="w-16 h-16 rounded-lg bg-slate-700 flex items-center justify-center text-xs text-slate-400 flex-shrink-0">+{photoCount - 6}</div>
                          )}
                        </div>
                      </div>
                    )}

                    {/* Bilingual Description Preview */}
                    {(p.public_remarks_es || p.public_remarks_en) && (
                      <div className="mb-4 bg-slate-900 rounded-xl p-3">
                        <div className="flex items-center justify-between mb-2">
                          <p className="text-xs text-slate-500">{lang === 'en' ? 'Description' : 'Descripción'}</p>
                          <div className="flex gap-1">
                            {['es', 'en'].map(l => (
                              <button key={l} onClick={() => setDescLang(l)}
                                className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase transition-all ${descLang === l ? 'bg-nexus-blue text-white' : 'bg-slate-800 text-slate-500 hover:text-white'}`}>
                                {l === 'es' ? '🇪🇸 ES' : '🇺🇸 EN'}
                              </button>
                            ))}
                          </div>
                        </div>
                        <p className="text-xs text-slate-300 line-clamp-4">
                          {descLang === 'en' ? (p.public_remarks_en || <span className="italic text-slate-500">{lang === 'en' ? 'No English description' : 'Sin descripción en inglés'}</span>) : (p.public_remarks_es || <span className="italic text-slate-500">{lang === 'en' ? 'No Spanish description' : 'Sin descripción en español'}</span>)}
                        </p>
                      </div>
                    )}

                    {/* Approval checklist */}
                    {p.status === 'pending_approval' && (
                      <div className="bg-slate-900 rounded-xl p-4 mb-4">
                        <p className="text-xs font-bold text-slate-300 uppercase tracking-wider mb-3">{lang === 'en' ? 'Approval Checklist' : 'Checklist de Aprobación'}</p>
                        <div className="space-y-1.5 text-sm">
                          <p className={p.owner_name ? 'text-green-400' : 'text-red-400'}>{p.owner_name ? '☑' : '☐'} {lang === 'en' ? 'Owner info verified' : 'Info propietario verificada'}</p>
                          <p className={p.listing_agreement ? 'text-green-400' : 'text-red-400'}>{p.listing_agreement ? '☑' : '☐'} {lang === 'en' ? 'Listing agreement signed' : 'Contrato firmado'}</p>
                          <p className={photoCount > 0 ? 'text-green-400' : 'text-amber-400'}>{photoCount > 0 ? '☑' : '☐'} {lang === 'en' ? `Photos uploaded (${photoCount})` : `Fotos subidas (${photoCount})`}</p>
                          <p className={p.list_price ? 'text-green-400' : 'text-red-400'}>{p.list_price ? '☑' : '☐'} {lang === 'en' ? 'Price set' : 'Precio establecido'}</p>
                          <p className={(p.public_remarks_es || p.public_remarks_en) ? 'text-green-400' : 'text-amber-400'}>{(p.public_remarks_es || p.public_remarks_en) ? '☑' : '☐'} {lang === 'en' ? 'Description written' : 'Descripción escrita'}</p>
                          <p className={p.property_type_id ? 'text-green-400' : 'text-amber-400'}>{p.property_type_id ? '☑' : '☐'} {lang === 'en' ? 'Property type set' : 'Tipo de propiedad definido'}</p>
                          <p className={p.location_id ? 'text-green-400' : 'text-amber-400'}>{p.location_id ? '☑' : '☐'} {lang === 'en' ? 'RECONNECT location ID' : 'Ubicación RECONNECT'}</p>
                          <p className={(p.listing_side_comm && p.selling_side_comm) ? 'text-green-400' : 'text-amber-400'}>{(p.listing_side_comm && p.selling_side_comm) ? '☑' : '☐'} {lang === 'en' ? 'Commission splits' : 'Splits de comisión'}</p>
                        </div>
                      </div>
                    )}

                    {/* Actions */}
                    {p.status === 'pending_approval' && (
                      <div className="flex flex-col gap-3">
                        <div className="flex items-center gap-2">
                          <button onClick={() => handleApprove(p.id)} disabled={actionLoading} className="px-5 py-2 rounded-xl bg-green-600 hover:bg-green-700 text-white text-sm font-semibold transition-all disabled:opacity-50">
                            ✅ {lang === 'en' ? 'Approve' : 'Aprobar'}
                          </button>
                          <button onClick={() => handleApproveAndPublish(p.id)} disabled={actionLoading} className="px-5 py-2 rounded-xl bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold transition-all disabled:opacity-50">
                            🚀 {lang === 'en' ? 'Approve & Publish' : 'Aprobar y Publicar'}
                          </button>
                        </div>
                        <div>
                          <textarea value={rejectNotes} onChange={e => setRejectNotes(e.target.value)} rows={2} placeholder={lang === 'en' ? 'Notes for the agent (required for rejection)...' : 'Notas para el agente (requeridas para rechazo)...'} className="w-full px-3 py-2 rounded-xl bg-slate-900 border border-slate-700 text-sm text-white placeholder-slate-500 resize-none outline-none focus:ring-1 focus:ring-amber-500" />
                          <button onClick={() => handleReject(p.id)} disabled={actionLoading} className="mt-2 px-5 py-2 rounded-xl bg-amber-600 hover:bg-amber-700 text-white text-sm font-semibold transition-all disabled:opacity-50">
                            ❌ {lang === 'en' ? 'Request Changes' : 'Necesita Cambios'}
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";
import { useState, useEffect, useMemo, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { useApp } from '@/lib/context';

/* ═══════════════════════════════════════════════════════════════
   WEBSITE ANALYTICS TAB — Broker Dashboard
   Aggregates page views, visitors, devices, referrers, and
   per-listing performance across all properties & developments.
   ═══════════════════════════════════════════════════════════════ */

const RANGE_OPTIONS = [
  { key: '7d',  days: 7 },
  { key: '30d', days: 30 },
  { key: '90d', days: 90 },
  { key: 'all', days: 365 },
];

export default function WebsiteAnalyticsTab({ properties = [], developments = [] }) {
  const { t, lang } = useApp();
  const [range, setRange] = useState('30d');
  const [dailyStats, setDailyStats] = useState([]);
  const [rawViews, setRawViews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [aggregating, setAggregating] = useState(false);

  const rangeDays = RANGE_OPTIONS.find(r => r.key === range)?.days || 30;
  const startDate = useMemo(() => {
    const d = new Date();
    d.setDate(d.getDate() - rangeDays);
    return d.toISOString().split('T')[0];
  }, [rangeDays]);

  // Fetch data
  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [{ data: daily }, { data: views }] = await Promise.all([
        supabase
          .from('listing_daily_stats')
          .select('*')
          .gte('stat_date', startDate)
          .order('stat_date', { ascending: false }),
        supabase
          .from('listing_page_views')
          .select('property_id, development_id, referrer, device_type, viewed_at, duration_seconds, session_id')
          .gte('viewed_at', startDate + 'T00:00:00Z')
          .order('viewed_at', { ascending: false })
          .limit(5000),
      ]);
      setDailyStats(daily || []);
      setRawViews(views || []);
    } catch (err) {
      console.error('Analytics load error:', err);
    } finally {
      setLoading(false);
    }
  }, [startDate]);

  useEffect(() => { loadData(); }, [loadData]);

  // Trigger aggregation
  const handleAggregate = async () => {
    setAggregating(true);
    try {
      const res = await fetch('/api/public/analytics/aggregate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ days: rangeDays }),
      });
      if (res.ok) loadData();
    } catch (err) {
      console.error('Aggregation error:', err);
    } finally {
      setAggregating(false);
    }
  };

  // ── Computed Metrics ──
  const metrics = useMemo(() => {
    const totalViews = dailyStats.reduce((s, d) => s + (d.total_views || 0), 0);
    const totalUnique = dailyStats.reduce((s, d) => s + (d.unique_visitors || 0), 0);
    const avgDuration = dailyStats.length > 0
      ? Math.round(dailyStats.reduce((s, d) => s + (d.avg_duration_seconds || 0), 0) / dailyStats.length)
      : 0;
    const mobilePct = dailyStats.length > 0
      ? Math.round(dailyStats.reduce((s, d) => s + (Number(d.mobile_pct) || 0), 0) / dailyStats.length)
      : 0;
    return { totalViews, totalUnique, avgDuration, mobilePct, desktopPct: 100 - mobilePct };
  }, [dailyStats]);

  // ── Daily chart data (last N days, filled gaps) ──
  const chartData = useMemo(() => {
    const days = [];
    for (let i = rangeDays - 1; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      days.push(d.toISOString().split('T')[0]);
    }
    const statsByDate = {};
    dailyStats.forEach(s => {
      if (!statsByDate[s.stat_date]) statsByDate[s.stat_date] = { views: 0, unique: 0 };
      statsByDate[s.stat_date].views += s.total_views || 0;
      statsByDate[s.stat_date].unique += s.unique_visitors || 0;
    });
    return days.map(date => ({
      date,
      views: statsByDate[date]?.views || 0,
      unique: statsByDate[date]?.unique || 0,
    }));
  }, [dailyStats, rangeDays]);

  const maxViews = Math.max(...chartData.map(d => d.views), 1);

  // ── Top referrers ──
  const topReferrers = useMemo(() => {
    const counts = {};
    rawViews.forEach(v => {
      if (!v.referrer) return;
      try {
        const host = new URL(v.referrer).hostname.replace('www.', '');
        counts[host] = (counts[host] || 0) + 1;
      } catch {
        counts[v.referrer] = (counts[v.referrer] || 0) + 1;
      }
    });
    return Object.entries(counts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 8)
      .map(([source, count]) => ({ source, count, pct: Math.round((count / (rawViews.length || 1)) * 100) }));
  }, [rawViews]);

  // ── Top listings by views ──
  const topListings = useMemo(() => {
    const propMap = {};
    properties.forEach(p => { propMap[p.id] = lang === 'es' ? (p.listing_title_es || p.name) : (p.listing_title_en || p.name); });
    const devMap = {};
    (developments || []).forEach(d => { devMap[d.id] = d.name; });

    const counts = {};
    dailyStats.forEach(s => {
      const key = s.property_id || s.development_id;
      if (!key) return;
      if (!counts[key]) counts[key] = { id: key, views: 0, unique: 0, type: s.property_id ? 'property' : 'development' };
      counts[key].views += s.total_views || 0;
      counts[key].unique += s.unique_visitors || 0;
    });

    return Object.values(counts)
      .sort((a, b) => b.views - a.views)
      .slice(0, 10)
      .map(item => ({
        ...item,
        name: item.type === 'property' ? (propMap[item.id] || t('ofc_wa_unknown_property')) : (devMap[item.id] || t('ofc_wa_unknown_dev')),
      }));
  }, [dailyStats, properties, developments, lang, t]);

  // ── Device breakdown ──
  const deviceBreakdown = useMemo(() => {
    const counts = { desktop: 0, mobile: 0, tablet: 0, unknown: 0 };
    rawViews.forEach(v => { counts[v.device_type] = (counts[v.device_type] || 0) + 1; });
    const total = rawViews.length || 1;
    return [
      { type: '🖥️ Desktop', count: counts.desktop, pct: Math.round((counts.desktop / total) * 100) },
      { type: '📱 Mobile', count: counts.mobile, pct: Math.round((counts.mobile / total) * 100) },
      { type: '📋 Tablet', count: counts.tablet, pct: Math.round((counts.tablet / total) * 100) },
    ].filter(d => d.count > 0);
  }, [rawViews]);

  // ── Helpers ──
  const formatDuration = (s) => {
    if (s < 60) return `${s}s`;
    return `${Math.floor(s / 60)}m ${s % 60}s`;
  };

  const formatDate = (d) => {
    const date = new Date(d + 'T12:00:00');
    return date.toLocaleDateString(lang === 'es' ? 'es-CR' : 'en-US', { month: 'short', day: 'numeric' });
  };

  const isEmpty = metrics.totalViews === 0 && rawViews.length === 0;

  return (
    <div className="space-y-6">
      {/* ── Header Actions ── */}
      <div className="flex flex-wrap items-center justify-between gap-3">
        {/* Range Selector */}
        <div className="flex bg-slate-100 dark:bg-slate-900/50 rounded-xl p-1">
          {RANGE_OPTIONS.map(r => (
            <button
              key={r.key}
              onClick={() => setRange(r.key)}
              className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
                range === r.key
                  ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm'
                  : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-300'
              }`}
            >
              {r.key === 'all' ? t('ofc_wa_range_all') : `${r.days}${t('ofc_wa_range_days')}`}
            </button>
          ))}
        </div>

        {/* Aggregate Button */}
        <button
          onClick={handleAggregate}
          disabled={aggregating}
          className="bg-slate-800 dark:bg-slate-700 hover:bg-slate-900 dark:hover:bg-slate-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg transition-all disabled:opacity-50 flex items-center gap-2"
        >
          {aggregating ? (
            <>
              <span className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
              {t('ofc_wa_aggregating')}
            </>
          ) : (
            <>
              <span>🔄</span> {t('ofc_wa_refresh')}
            </>
          )}
        </button>
      </div>

      {/* ── Empty State ── */}
      {!loading && isEmpty ? (
        <div className="text-center py-16 space-y-4">
          <div className="text-6xl">📊</div>
          <h3 className="text-lg font-black italic text-slate-900 dark:text-white">
            {t('ofc_wa_empty_title')}
          </h3>
          <p className="text-sm text-slate-400 max-w-md mx-auto">
            {t('ofc_wa_empty_desc')}
          </p>
          <div className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-5 max-w-lg mx-auto text-left mt-6 border border-slate-200 dark:border-slate-700">
            <p className="text-[10px] text-slate-500 uppercase font-bold mb-3">{t('ofc_wa_embed_title')}</p>
            <code className="text-[11px] text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 rounded-lg p-3 block whitespace-pre-wrap break-all font-mono">
{`<script
  src="https://hub.remax-altitud.cr/tracker/altitud-tracker.js"
  data-hub-url="https://hub.remax-altitud.cr"
  data-property-id="PROPERTY_UUID"
  async></script>`}
            </code>
          </div>
        </div>
      ) : loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="w-8 h-8 border-3 border-nexus-blue border-t-transparent rounded-full animate-spin" />
        </div>
      ) : (
        <>
          {/* ── Stats Grid ── */}
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
            {[
              { label: t('ofc_wa_total_views'), val: metrics.totalViews.toLocaleString(), color: 'text-slate-900 dark:text-white', icon: '👁️' },
              { label: t('ofc_wa_unique_visitors'), val: metrics.totalUnique.toLocaleString(), color: 'text-blue-500', icon: '👤' },
              { label: t('ofc_wa_avg_time'), val: formatDuration(metrics.avgDuration), color: 'text-emerald-500', icon: '⏱️' },
              { label: t('ofc_wa_mobile'), val: `${metrics.mobilePct}%`, color: 'text-purple-500', icon: '📱' },
              { label: t('ofc_wa_desktop'), val: `${metrics.desktopPct}%`, color: 'text-amber-500', icon: '🖥️' },
            ].map((s, i) => (
              <div key={i} className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-4 border border-slate-100 dark:border-slate-700 group hover:shadow-md transition-all">
                <div className="flex items-center gap-2 mb-2">
                  <span className="text-sm">{s.icon}</span>
                  <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{s.label}</p>
                </div>
                <p className={`text-2xl font-black italic tabular-nums ${s.color}`}>{s.val}</p>
              </div>
            ))}
          </div>

          {/* ── Views Chart ── */}
          <div className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-5 border border-slate-100 dark:border-slate-700">
            <div className="flex items-center justify-between mb-4">
              <h4 className="text-sm font-black uppercase tracking-widest text-slate-900 dark:text-white">{t('ofc_wa_views_over_time')}</h4>
              <span className="text-[10px] text-slate-400 font-bold">{chartData.reduce((s, d) => s + d.views, 0).toLocaleString()} {t('ofc_wa_total_label')}</span>
            </div>

            {/* Bar Chart */}
            <div className="flex items-end gap-[2px] h-32">
              {chartData.map((d, i) => {
                const heightPct = Math.max((d.views / maxViews) * 100, 2);
                const showLabel = chartData.length <= 30 || i % Math.ceil(chartData.length / 15) === 0;
                return (
                  <div key={i} className="flex-1 flex flex-col items-center gap-1 group relative">
                    <div
                      className="w-full bg-gradient-to-t from-blue-500 to-blue-400 dark:from-blue-600 dark:to-blue-500 rounded-sm transition-all group-hover:from-blue-600 group-hover:to-blue-500 cursor-default relative"
                      style={{ height: `${heightPct}%`, minHeight: '2px' }}
                    >
                      {/* Tooltip */}
                      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-1 bg-slate-800 text-white text-[9px] px-2 py-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none z-10">
                        {formatDate(d.date)}: {d.views} {t('ofc_wa_views_label')}
                      </div>
                    </div>
                    {showLabel && (
                      <span className="text-[7px] text-slate-400 font-bold mt-0.5 whitespace-nowrap">
                        {new Date(d.date + 'T12:00:00').getDate()}
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* ── Two-Column Layout ── */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">

            {/* Top Listings */}
            <div className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-5 border border-slate-100 dark:border-slate-700">
              <h4 className="text-sm font-black uppercase tracking-widest text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                <span>🏆</span> {t('ofc_wa_top_listings')}
              </h4>
              {topListings.length === 0 ? (
                <p className="text-xs text-slate-400 italic">{t('ofc_wa_no_listing_data')}</p>
              ) : (
                <div className="space-y-2">
                  {topListings.map((item, i) => {
                    const barWidth = Math.max((item.views / (topListings[0]?.views || 1)) * 100, 5);
                    return (
                      <div key={item.id} className="group">
                        <div className="flex items-center gap-3 mb-1">
                          <span className={`text-[10px] font-black w-5 text-right tabular-nums ${i < 3 ? 'text-amber-500' : 'text-slate-400'}`}>
                            {i + 1}.
                          </span>
                          <span className="flex-1 text-xs font-bold text-slate-700 dark:text-slate-300 truncate">
                            {item.name}
                          </span>
                          <span className={`text-[8px] font-bold uppercase px-1.5 py-0.5 rounded-full ${
                            item.type === 'property'
                              ? 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400'
                              : 'bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400'
                          }`}>
                            {item.type === 'property' ? '🏠' : '🏗️'}
                          </span>
                          <span className="text-xs font-black text-slate-900 dark:text-white tabular-nums w-12 text-right">{item.views}</span>
                        </div>
                        <div className="ml-8 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                          <div
                            className="h-full bg-gradient-to-r from-blue-400 to-blue-600 rounded-full transition-all duration-700"
                            style={{ width: `${barWidth}%` }}
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>

            {/* Traffic Sources + Devices */}
            <div className="space-y-4">
              {/* Top Referrers */}
              <div className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-5 border border-slate-100 dark:border-slate-700">
                <h4 className="text-sm font-black uppercase tracking-widest text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                  <span>🔗</span> {t('ofc_wa_traffic_sources')}
                </h4>
                {topReferrers.length === 0 ? (
                  <p className="text-xs text-slate-400 italic">{t('ofc_wa_no_referrer_data')}</p>
                ) : (
                  <div className="space-y-2.5">
                    {topReferrers.map((r, i) => (
                      <div key={i} className="flex items-center gap-3">
                        <span className="text-xs text-slate-500 truncate flex-1 max-w-[60%]">{r.source}</span>
                        <div className="flex-1 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                          <div
                            className="h-full bg-gradient-to-r from-emerald-400 to-emerald-600 rounded-full"
                            style={{ width: `${r.pct}%` }}
                          />
                        </div>
                        <span className="text-[10px] font-black text-slate-600 dark:text-slate-300 tabular-nums w-10 text-right">{r.count}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Device Breakdown */}
              <div className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-5 border border-slate-100 dark:border-slate-700">
                <h4 className="text-sm font-black uppercase tracking-widest text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                  <span>📱</span> {t('ofc_wa_devices')}
                </h4>
                {deviceBreakdown.length === 0 ? (
                  <p className="text-xs text-slate-400 italic">{t('ofc_wa_no_device_data')}</p>
                ) : (
                  <div className="space-y-3">
                    {deviceBreakdown.map((d, i) => (
                      <div key={i}>
                        <div className="flex justify-between mb-1">
                          <span className="text-xs font-bold text-slate-600 dark:text-slate-300">{d.type}</span>
                          <span className="text-xs font-black text-slate-900 dark:text-white tabular-nums">{d.pct}%</span>
                        </div>
                        <div className="h-2 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                          <div
                            className={`h-full rounded-full transition-all duration-700 ${
                              i === 0 ? 'bg-gradient-to-r from-blue-400 to-blue-600'
                              : i === 1 ? 'bg-gradient-to-r from-purple-400 to-purple-600'
                              : 'bg-gradient-to-r from-amber-400 to-amber-600'
                            }`}
                            style={{ width: `${d.pct}%` }}
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* ── Embed Code Snippet ── */}
          <div className="bg-slate-50 dark:bg-slate-900/50 rounded-2xl p-5 border border-slate-100 dark:border-slate-700">
            <div className="flex items-center gap-3 mb-3">
              <span className="text-lg">🧩</span>
              <div>
                <h4 className="text-sm font-black uppercase tracking-widest text-slate-900 dark:text-white">{t('ofc_wa_embed_title')}</h4>
                <p className="text-[10px] text-slate-400 mt-0.5">{t('ofc_wa_embed_desc')}</p>
              </div>
            </div>
            <code className="text-[11px] text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/20 rounded-lg p-3 block whitespace-pre-wrap break-all font-mono">
{`<script src="https://hub.remax-altitud.cr/tracker/altitud-tracker.js"
  data-hub-url="https://hub.remax-altitud.cr"
  data-property-id="YOUR_PROPERTY_UUID"
  async></script>`}
            </code>
          </div>
        </>
      )}
